    // Undo/redo are special — they don't go through the timeline module's responder chain.
    // Instead we need to find the document's undo manager directly. The path is:
    // PEAppController -> _targetLibrary -> libraryDocument -> undoManager
    if ([action isEqualToString:@"undo"] || [action isEqualToString:@"redo"]) {
        __block NSDictionary *undoResult = nil;
        SpliceKit_executeOnMainThread(^{
            @try {
                id app = ((id (*)(id, SEL))objc_msgSend)(
                    objc_getClass("NSApplication"), @selector(sharedApplication));
                id delegate = ((id (*)(id, SEL))objc_msgSend)(app, @selector(delegate));
                // PEAppController -> _targetLibrary -> libraryDocument -> undoManager
                SEL libSel = NSSelectorFromString(@"_targetLibrary");
                id library = nil;
                if ([delegate respondsToSelector:libSel]) {
                    library = ((id (*)(id, SEL))objc_msgSend)(delegate, libSel);
                }
                if (!library) {
                    // Fallback: get first active library
                    id libs = ((id (*)(id, SEL))objc_msgSend)(
                        objc_getClass("FFLibraryDocument"), @selector(copyActiveLibraries));
                    if ([libs respondsToSelector:@selector(firstObject)]) {
                        library = ((id (*)(id, SEL))objc_msgSend)(libs, @selector(firstObject));
                    }
                }
                if (!library) {
                    undoResult = @{@"error": @"No library found for undo"};
                    return;
                }
                id doc = ((id (*)(id, SEL))objc_msgSend)(library, @selector(libraryDocument));
                if (!doc) {
                    undoResult = @{@"error": @"No document found for undo"};
                    return;
                }
                id um = ((id (*)(id, SEL))objc_msgSend)(doc, @selector(undoManager));
                if (!um) {
                    undoResult = @{@"error": @"No undo manager"};
                    return;
                }

                SEL undoSel = [action isEqualToString:@"undo"] ? @selector(undo) : @selector(redo);
                SEL canSel = [action isEqualToString:@"undo"] ? @selector(canUndo) : @selector(canRedo);
                SEL nameSel = [action isEqualToString:@"undo"] ? @selector(undoActionName) : @selector(redoActionName);

                BOOL can = ((BOOL (*)(id, SEL))objc_msgSend)(um, canSel);
                if (!can) {
                    undoResult = @{@"error": [NSString stringWithFormat:@"Cannot %@ - nothing to %@", action, action]};
                    return;
                }

                NSString *actionName = ((id (*)(id, SEL))objc_msgSend)(um, nameSel);
                ((void (*)(id, SEL))objc_msgSend)(um, undoSel);
                undoResult = @{@"action": action, @"status": @"ok",
                              @"actionName": actionName ?: @""};
            } @catch (NSException *e) {
                undoResult = @{@"error": [NSString stringWithFormat:@"Exception: %@", e.reason]};
            }
        });
        return undoResult;
    }

    // Add transition to ALL edit points: select all → addTransition
    // FCP natively adds transitions at every edit point when all clips are selected.
    if ([action isEqualToString:@"addTransitionToAll"]) {
        __block NSDictionary *allResult = nil;
        SpliceKit_executeOnMainThread(^{
            @try {
                id timelineModule = SpliceKit_getActiveTimelineModule();
                if (!timelineModule) {
                    allResult = @{@"error": @"No active timeline module"};
                    return;
                }

                NSUInteger before = SpliceKit_transitionCount(timelineModule);

                // Select all clips
                SEL selectAllSel = @selector(selectAll:);
                if ([timelineModule respondsToSelector:selectAllSel]) {
                    ((void (*)(id, SEL, id))objc_msgSend)(timelineModule, selectAllSel, nil);
                } else {
                    [[NSApplication sharedApplication] sendAction:selectAllSel to:nil from:nil];
                }

                // Let selection register
                [[NSRunLoop currentRunLoop] runUntilDate:
                    [NSDate dateWithTimeIntervalSinceNow:0.15]];

                // Add transition — FCP adds to all edit points when all clips selected
                SEL addSel = @selector(addTransition:);
                if ([timelineModule respondsToSelector:addSel]) {
                    ((void (*)(id, SEL, id))objc_msgSend)(timelineModule, addSel, nil);
                } else {
                    [[NSApplication sharedApplication] sendAction:addSel to:nil from:nil];
                }

                // Wait for transitions to appear
                [[NSRunLoop currentRunLoop] runUntilDate:
                    [NSDate dateWithTimeIntervalSinceNow:0.5]];

                NSUInteger after = SpliceKit_transitionCount(timelineModule);
                NSUInteger added = (after > before) ? (after - before) : 0;

                SpliceKit_log(@"[Transition] Added %lu transitions to all edit points (total: %lu)",
                              (unsigned long)added, (unsigned long)after);

                allResult = @{
                    @"action": @"addTransitionToAll",
                    @"status": @"ok",
                    @"transitionsAdded": @(added),
                    @"totalTransitions": @(after)
                };
            } @catch (NSException *e) {
                allResult = @{@"error": [NSString stringWithFormat:@"Exception: %@", e.reason]};
            }
        });
        return allResult ?: @{@"error": @"Failed to add transitions to all clips"};
    }

    if ([action isEqualToString:@"removeAllKeyframesFromClip"]) {
        __block NSDictionary *clearResult = nil;
        SpliceKit_executeOnMainThread(^{
            @try {
                id timelineModule = SpliceKit_getActiveTimelineModule();
                if (!timelineModule) {
                    clearResult = @{@"error": @"No active timeline module"};
                    return;
                }

                BOOL autoSelected = NO;
                id clip = SpliceKit_getSelectedTimelineItem(timelineModule);
                if (!clip) {
                    SEL selectAtPlayhead = NSSelectorFromString(@"selectClipAtPlayhead:");
                    if ([timelineModule respondsToSelector:selectAtPlayhead]) {
                        ((void (*)(id, SEL, id))objc_msgSend)(timelineModule, selectAtPlayhead, nil);
                    } else {
                        [[NSApplication sharedApplication] sendAction:selectAtPlayhead to:nil from:nil];
                    }
                    autoSelected = YES;
                    [[NSRunLoop currentRunLoop] runUntilDate:
                        [NSDate dateWithTimeIntervalSinceNow:0.05]];
                    clip = SpliceKit_getSelectedTimelineItem(timelineModule);
                }

                if (!clip) {
                    clearResult = @{@"error": @"No clip selected and none found at playhead"};
                    return;
                }

                NSUInteger channelsCleared = 0;
                NSUInteger keyframesRemoved = 0;
                NSMutableArray *targetResults = [NSMutableArray array];
                for (id target in SpliceKit_keyframeTargetsForClip(clip)) {
                    NSDictionary *targetResult = SpliceKit_removeAllKeyframesFromEffectStack(
                        target, @"Remove All Keyframes");
                    if (!targetResult) continue;
                    channelsCleared += [targetResult[@"channelsCleared"] unsignedIntegerValue];
                    keyframesRemoved += [targetResult[@"keyframesRemoved"] unsignedIntegerValue];
                    [targetResults addObject:targetResult];
                }

                NSMutableDictionary *payload = [@{
                    @"action": @"removeAllKeyframesFromClip",
                    @"status": @"ok",
                    @"channelsCleared": @(channelsCleared),
                    @"keyframesRemoved": @(keyframesRemoved),
                    @"autoSelected": @(autoSelected),
                } mutableCopy];

                if (targetResults.count > 0) payload[@"targets"] = targetResults;
                @try {
                    if ([clip respondsToSelector:@selector(displayName)]) {
                        id name = ((id (*)(id, SEL))objc_msgSend)(clip, @selector(displayName));
                        if (name) payload[@"clipName"] = [name description];
                    }
                } @catch (NSException *e) {}
                payload[@"selectedClass"] = NSStringFromClass([clip class]);

                if (channelsCleared == 0) {
                    payload[@"note"] = @"No keyframed channels found on the selected clip";
                }
                SpliceKit_log(@"[Keyframes] removeAllKeyframesFromClip class=%@ channels=%lu keyframes=%lu",
                              NSStringFromClass([clip class]),
                              (unsigned long)channelsCleared,
                              (unsigned long)keyframesRemoved);
                clearResult = payload;
            } @catch (NSException *e) {
                clearResult = @{@"error": [NSString stringWithFormat:@"Exception: %@", e.reason]};
            }
        });
        return clearResult ?: @{@"error": @"Failed to remove keyframes from clip"};
    }

    // === Toggle Mute Audio ===
    // Mutes or unmutes audio on selected clips (or clip at playhead if nothing selected).
    // Works like "Disable Clip" (V) but for the audio portion only.
    // Uses FFAnchoredTimelineModule's native doMute: which toggles audioPlayEnable.
    if ([action isEqualToString:@"toggleMuteAudio"]) {
        __block NSDictionary *muteResult = nil;
        SpliceKit_executeOnMainThread(^{
            @try {
                id timelineModule = SpliceKit_getActiveTimelineModule();
                if (!timelineModule) {
                    muteResult = @{@"error": @"No active timeline module"};
                    return;
                }

                // Check for selected items
                SEL selectedSel = NSSelectorFromString(@"selectedItems");
                id selectedItems = nil;
                if ([timelineModule respondsToSelector:selectedSel]) {
                    selectedItems = ((id (*)(id, SEL))objc_msgSend)(timelineModule, selectedSel);
                }

                // If nothing selected, select clip at playhead first
                BOOL autoSelected = NO;
                if (!selectedItems || [selectedItems count] == 0) {
                    SEL selectAtPlayhead = NSSelectorFromString(@"selectClipAtPlayhead:");
                    if ([timelineModule respondsToSelector:selectAtPlayhead]) {
                        ((void (*)(id, SEL, id))objc_msgSend)(timelineModule, selectAtPlayhead, nil);
                        autoSelected = YES;
                    } else {
                        [[NSApplication sharedApplication] sendAction:selectAtPlayhead to:nil from:nil];
                        autoSelected = YES;
                    }
                    // Let selection register
                    [[NSRunLoop currentRunLoop] runUntilDate:
                        [NSDate dateWithTimeIntervalSinceNow:0.05]];
                    // Re-read selection
                    if ([timelineModule respondsToSelector:selectedSel]) {
                        selectedItems = ((id (*)(id, SEL))objc_msgSend)(timelineModule, selectedSel);
                    }
                }

                if (!selectedItems || [selectedItems count] == 0) {
                    muteResult = @{@"error": @"No clip selected and none found at playhead"};
                    return;
                }

                // Use FCP's built-in adjustVolumeByAmount:isRelative:actionName: on the
                // timeline module. Mute sets -96 dB (silence), unmute restores to 0 dB.
                // This handles all clip types, undo, and connected storylines natively.
                //
                // Detect muted state by reading the audio volume channel from the
                // selected clip's effect stack.
                SEL adjustVolSel = NSSelectorFromString(@"adjustVolumeByAmount:isRelative:actionName:");
                if (![timelineModule respondsToSelector:adjustVolSel]) {
                    muteResult = @{@"error": @"Timeline module does not support volume adjustment"};
                    return;
                }

                // Detect muted state via newVolume.amount on the first selected clip.
                // FFAnchoredObject.newVolume returns an IXVolume; its amount is e.g. "0dB" or "-96dB".
                BOOL isMuted = NO;
                SEL newVolSel = NSSelectorFromString(@"newVolume");
                for (id item in selectedItems) {
                    if (![item respondsToSelector:newVolSel]) continue;
                    id vol = ((id (*)(id, SEL))objc_msgSend)(item, newVolSel);
                    if (!vol) continue;
                    id amountStr = ((id (*)(id, SEL))objc_msgSend)(vol, @selector(amount));
                    if (amountStr && [amountStr isKindOfClass:[NSString class]]) {
                        if ([amountStr hasPrefix:@"-96"]) isMuted = YES;
                    }
                    break;
                }

                BOOL shouldMute = !isMuted;
                NSString *actionName = shouldMute ? @"Mute Audio" : @"Unmute Audio";

                if (shouldMute) {
                    // Mute: set volume to -96 dB (silence)
                    ((void (*)(id, SEL, double, BOOL, id))objc_msgSend)(
                        timelineModule, adjustVolSel, -96.0, NO, actionName);
                } else {
                    // Unmute: undo the mute (restore previous volume via undo manager)
                    id um = SpliceKit_getUndoManager();
                    if (um && ((BOOL (*)(id, SEL))objc_msgSend)(um, @selector(canUndo))) {
                        NSString *undoName = ((id (*)(id, SEL))objc_msgSend)(um, @selector(undoActionName));
                        if ([undoName containsString:@"Mute"] || [undoName containsString:@"Volume"]) {
                            ((void (*)(id, SEL))objc_msgSend)(um, @selector(undo));
                        } else {
                            // No mute action to undo — set to 0 dB as fallback
                            ((void (*)(id, SEL, double, BOOL, id))objc_msgSend)(
                                timelineModule, adjustVolSel, 0.0, NO, actionName);
                        }
                    } else {
                        // No undo available — set to 0 dB as fallback
                        ((void (*)(id, SEL, double, BOOL, id))objc_msgSend)(
                            timelineModule, adjustVolSel, 0.0, NO, actionName);
                    }
                }

                NSUInteger count = [selectedItems count];
                SpliceKit_log(@"[Audio] %@ audio on %lu clip(s)%s",
                              actionName,
                              (unsigned long)count,
                              autoSelected ? " (auto-selected at playhead)" : "");
                muteResult = @{
                    @"action": @"toggleMuteAudio",
                    @"status": @"ok",
                    @"audioMuted": @(shouldMute),
                    @"clipCount": @(count),
                    @"autoSelected": @(autoSelected)
                };
            } @catch (NSException *e) {
                muteResult = @{@"error": [NSString stringWithFormat:@"Exception: %@", e.reason]};
            }
        });
        return muteResult ?: @{@"error": @"Failed to toggle audio mute"};
    }

    NSString *selector = actionMap[action];
    if (!selector) {
        // Allow passing raw selector names too
        selector = action;
        if (![selector hasSuffix:@":"]) {
            selector = [selector stringByAppendingString:@":"];
        }
    }

    // Paste gets special treatment: FCP's own paste: only knows about its native
    // pasteboard format (FFPasteboardItem). If someone put FCPXML on the clipboard
    // instead, we need to route it through our XML import path or it'll be silently ignored.
    if ([action isEqualToString:@"paste"]) {
        __block BOOL hasXML = NO;
        SpliceKit_executeOnMainThread(^{
            NSPasteboard *pb = [NSPasteboard generalPasteboard];
            SEL containsXMLSel = NSSelectorFromString(@"containsXML");
            if ([pb respondsToSelector:containsXMLSel]) {
                hasXML = ((BOOL (*)(id, SEL))objc_msgSend)(pb, containsXMLSel);
            }
            // Also check if it's NOT native (native takes priority)
            if (hasXML) {
                NSString *nativeType = @"com.apple.flexo.proFFPasteboardUTI";
                if ([[pb types] containsObject:nativeType]) {
                    hasXML = NO; // Native data present, use normal paste path
                }
            }
        });
        if (hasXML) {
            return SpliceKit_handlePasteboardImportXML(@{});
        }
    }

    // addTodoMarker: doesn't exist as an IBAction on FFAnchoredTimelineModule or in the
    // responder chain. Use the direct sequence method that batch markers also uses.
    if ([action isEqualToString:@"addTodoMarker"]) {
        __block NSDictionary *todoResult = nil;
        SpliceKit_executeOnMainThread(^{
            @try {
                id timeline = SpliceKit_getActiveTimelineModule();
                if (!timeline) { todoResult = @{@"error": @"No active timeline module. Is a project open?"}; return; }

                id sequence = ((id (*)(id, SEL))objc_msgSend)(timeline, @selector(sequence));
                if (!sequence) { todoResult = @{@"error": @"No sequence in timeline"}; return; }

                // Get playhead time for marker position
                SpliceKit_CMTime playheadTime = ((SpliceKit_CMTime (*)(id, SEL))STRET_MSG)(timeline, @selector(playheadTime));
                SpliceKit_CMTime frameDur = {100, 2400, 1, 0};
                SEL fdSel = NSSelectorFromString(@"frameDuration");
                if ([sequence respondsToSelector:fdSel]) {
                    SpliceKit_CMTime fd = ((SpliceKit_CMTime (*)(id, SEL))STRET_MSG)(sequence, fdSel);
                    if (fd.timescale > 0) frameDur = fd;
                }

                // Find the clip at the playhead
                id primaryObj = [sequence respondsToSelector:@selector(primaryObject)]
                    ? ((id (*)(id, SEL))objc_msgSend)(sequence, @selector(primaryObject)) : nil;
                id targetClip = primaryObj; // fallback to primary object
                if (primaryObj && [primaryObj respondsToSelector:@selector(containedItems)]) {
                    id items = ((id (*)(id, SEL))objc_msgSend)(primaryObj, @selector(containedItems));
                    if ([items isKindOfClass:[NSArray class]]) {
                        SEL erSel = NSSelectorFromString(@"effectiveRangeOfObject:");
                        if ([primaryObj respondsToSelector:erSel]) {
                            for (id item in (NSArray *)items) {
                                @try {
                                    SpliceKit_CMTimeRange range = ((SpliceKit_CMTimeRange (*)(id, SEL, id))STRET_MSG)(
                                        primaryObj, erSel, item);
                                    double clipStart = (range.start.timescale > 0) ? (double)range.start.value / range.start.timescale : 0;
                                    double clipDur = (range.duration.timescale > 0) ? (double)range.duration.value / range.duration.timescale : 0;
                                    double ph = (playheadTime.timescale > 0) ? (double)playheadTime.value / playheadTime.timescale : 0;
                                    if (ph >= clipStart - 0.01 && ph < clipStart + clipDur + 0.01) {
                                        targetClip = item;
                                        break;
                                    }
                                } @catch (NSException *e) {}
                            }
                        }
                    }
                }

                SEL addSel = NSSelectorFromString(@"actionAddMarkerToAnchoredObject:isToDo:isChapter:withRange:error:");
                if (![sequence respondsToSelector:addSel]) {
                    todoResult = @{@"error": @"Sequence does not support actionAddMarkerToAnchoredObject:"};
                    return;
                }

                SpliceKit_CMTimeRange range = {playheadTime, frameDur};
                NSError *err = nil;
                typedef BOOL (*AddMarkerFn)(id, SEL, id, BOOL, BOOL, SpliceKit_CMTimeRange, NSError **);
                BOOL ok = ((AddMarkerFn)objc_msgSend)(sequence, addSel, targetClip, YES, NO, range, &err);
                if (ok) {
                    todoResult = @{@"action": @"addTodoMarker", @"status": @"ok"};
                } else {
                    todoResult = @{@"error": err ? [err localizedDescription] : @"Failed to add todo marker"};
                }
            } @catch (NSException *e) {
                todoResult = @{@"error": [NSString stringWithFormat:@"Exception: %@", e.reason]};
            }
        });
        return todoResult ?: @{@"error": @"Failed to add todo marker"};
    }

    // First try on the timeline module directly (fastest, most specific)
    NSDictionary *result = SpliceKit_sendTimelineAction(selector);

    // If timeline module doesn't respond, fall back to responder chain
    if (result[@"error"]) {
        NSString *errMsg = result[@"error"];
        if ([errMsg containsString:@"does not respond"] || [errMsg containsString:@"No active"]) {
            return SpliceKit_sendAppAction(selector);
        }
    }

    return result;
}

#pragma mark - Direct Flexo Action Methods (Parameterized)
//
// The actionMap above handles simple IBAction-style methods (void return, sender arg).
// But many of Flexo's editing methods take real parameters — rates, time values,
// error pointers, item arrays. This handler provides access to those richer APIs.
//
// Clients can either use friendly names ("retimeSetRate" with rate/ripple params)
// or pass raw selectors for full control. The friendly names are preferred because
// they handle parameter marshaling and validation.
//

NSDictionary *SpliceKit_handleDirectTimelineAction(NSDictionary *params) {
    NSString *action = params[@"action"];
    NSString *rawSelector = params[@"selector"];

    if (!action && !rawSelector) {
        return @{@"error": @"action or selector parameter required"};
    }

    __block NSDictionary *result = nil;

    SpliceKit_executeOnMainThread(^{
        @try {
            id timeline = SpliceKit_getActiveTimelineModule();
            if (!timeline) {
                result = @{@"error": @"No active timeline module. Is a project open?"};
                return;
            }

            // Get the root item (primaryObject of the sequence) - needed by most action methods
            id sequence = ((id (*)(id, SEL))objc_msgSend)(timeline,
                NSSelectorFromString(@"sequence"));
            id rootItem = nil;
            if (sequence) {
                rootItem = ((id (*)(id, SEL))objc_msgSend)(sequence,
                    NSSelectorFromString(@"primaryObject"));
            }

            // Helper: get selected items
            id (^getSelectedItems)(void) = ^{
                SEL selSel = NSSelectorFromString(@"selectedItems");
                if ([timeline respondsToSelector:selSel]) {
                    return ((id (*)(id, SEL))objc_msgSend)(timeline, selSel);
                }
                return (id)nil;
            };

            // === Marker Operations ===
            // Markers are owned by the sequence, not the timeline module. The action
            // methods live on FFAnchoredSequence and take the marker object directly.

            if ([action isEqualToString:@"changeMarkerType"]) {
                // Change marker type: "chapter", "todo", "note"
                NSString *type = params[@"type"] ?: @"note";
                SEL sel;
                if ([type isEqualToString:@"chapter"]) {
                    sel = NSSelectorFromString(@"actionChangeMarkerTypeToChapter:error:");
                } else if ([type isEqualToString:@"todo"]) {
                    sel = NSSelectorFromString(@"actionChangeMarkerTypeToTodo:error:");
                } else {
                    sel = NSSelectorFromString(@"actionChangeMarkerTypeToNote:error:");
                }
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                ((void (*)(id, SEL, id, NSError **))objc_msgSend)(timeline, sel, selectedItems, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"type": type, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"changeMarkerName"]) {
                // Rename a marker: requires marker handle and new name
                NSString *name = params[@"name"];
                NSString *markerHandle = params[@"marker"];
                if (!name) { result = @{@"error": @"name parameter required"}; return; }
                id marker = markerHandle ? SpliceKit_resolveHandle(markerHandle) : nil;
                if (!marker) {
                    // Try to use selected marker
                    id selected = getSelectedItems();
                    if ([selected respondsToSelector:@selector(firstObject)]) {
                        marker = ((id (*)(id, SEL))objc_msgSend)(selected, @selector(firstObject));
                    }
                }
                if (!marker) { result = @{@"error": @"No marker found. Select a marker or pass marker handle."}; return; }
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionChangeMarkerDisplayName:marker:error:");
                ((void (*)(id, SEL, id, id, NSError **))objc_msgSend)(timeline, sel, name, marker, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"name": name, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"markMarkerCompleted"]) {
                // Mark a todo marker as completed
                id marker = params[@"marker"] ? SpliceKit_resolveHandle(params[@"marker"]) : nil;
                if (!marker) {
                    id selected = getSelectedItems();
                    if ([selected respondsToSelector:@selector(firstObject)]) {
                        marker = ((id (*)(id, SEL))objc_msgSend)(selected, @selector(firstObject));
                    }
                }
                if (!marker) { result = @{@"error": @"No marker found"}; return; }
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionMarkMarkerAsCompleted:marker:error:");
                BOOL completed = [params[@"completed"] boolValue];
                ((void (*)(id, SEL, BOOL, id, NSError **))objc_msgSend)(timeline, sel, completed, marker, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"removeMarker"]) {
                id marker = params[@"marker"] ? SpliceKit_resolveHandle(params[@"marker"]) : nil;
                if (!marker) { result = @{@"error": @"marker handle required"}; return; }
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionRemoveMarker:error:");
                ((void (*)(id, SEL, id, NSError **))objc_msgSend)(timeline, sel, marker, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            // === Retiming / Speed (Direct API) ===
            // These call Flexo's parameterized retime methods directly, bypassing the
            // simple IBAction wrappers. They give precise control over rate, ripple
            // behavior, and variable speed settings. Each one operates on selected items.

            if ([action isEqualToString:@"retimeSetRate"]) {
                // Set exact retime rate with ripple control
                double rate = [params[@"rate"] doubleValue];
                BOOL ripple = [params[@"ripple"] boolValue];
                BOOL allowVariable = params[@"allowVariableSpeed"] ? [params[@"allowVariableSpeed"] boolValue] : YES;
                if (rate <= 0) { result = @{@"error": @"rate must be > 0 (e.g. 0.5 for half speed, 2.0 for double)"}; return; }
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionRetimeSetRatePreset:rate:ripple:allowVariableSpeedRetiming:objectsAndNewRanges:error:");
                ((void (*)(id, SEL, id, double, BOOL, BOOL, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, rate, ripple, allowVariable, nil, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"rate": @(rate), @"ripple": @(ripple), @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"retimeHoldPreset"]) {
                // Insert a hold/freeze frame at a specific time
                // This is the direct API for freeze-extend
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionRetimeHoldPreset:holdComponentTime:duration:newHoldComponentTime:error:");
                // holdComponentTime and duration come from the selected clip context
                ((void (*)(id, SEL, id, id, id, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, nil, nil, nil, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"retimeReverse"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionRetimeReverseClipPreset:error:");
                ((void (*)(id, SEL, id, NSError **))objc_msgSend)(timeline, sel, selectedItems, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"retimeBladeSpeedPreset"]) {
                // Blade at a speed segment boundary
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionRetimeBladeSpeedPreset:componentTime:newComponentTime:error:");
                ((void (*)(id, SEL, id, id, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, nil, nil, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"retimeSpeedRamp"]) {
                BOOL toZero = [params[@"toZero"] boolValue];
                BOOL fromZero = [params[@"fromZero"] boolValue];
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionRetimeSpeedRampPreset:startComponentTime:endComponentTime:toZero:fromZero:error:");
                ((void (*)(id, SEL, id, id, id, BOOL, BOOL, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, nil, nil, toZero, fromZero, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"toZero": @(toZero), @"fromZero": @(fromZero), @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"retimeInstantReplay"]) {
                double rate = params[@"rate"] ? [params[@"rate"] doubleValue] : 0.5;
                BOOL allowVariable = params[@"allowVariableSpeed"] ? [params[@"allowVariableSpeed"] boolValue] : YES;
                BOOL addTitle = params[@"addTitle"] ? [params[@"addTitle"] boolValue] : YES;
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionRetimeInstantReplayPreset:range:rate:allowVariableSpeedRetiming:addTitle:objectsAndNewRanges:error:");
                ((void (*)(id, SEL, id, id, double, BOOL, BOOL, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, nil, rate, allowVariable, addTitle, nil, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"rate": @(rate), @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"retimeJumpCut"]) {
                int framesToJump = params[@"framesToJump"] ? [params[@"framesToJump"] intValue] : 5;
                BOOL allowVariable = params[@"allowVariableSpeed"] ? [params[@"allowVariableSpeed"] boolValue] : YES;
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionRetimeJumpCutPreset:framesToJump:allowVariableSpeedRetiming:error:");
                ((void (*)(id, SEL, id, int, BOOL, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, framesToJump, allowVariable, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"framesToJump": @(framesToJump), @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"retimeRewind"]) {
                double rewindSpeed = params[@"speed"] ? [params[@"speed"] doubleValue] : 2.0;
                BOOL allowVariable = params[@"allowVariableSpeed"] ? [params[@"allowVariableSpeed"] boolValue] : YES;
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionRetimeRewindPreset:rewindSpeed:allowVariableSpeedRetiming:objectsAndNewRanges:error:");
                ((void (*)(id, SEL, id, double, BOOL, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, rewindSpeed, allowVariable, nil, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"speed": @(rewindSpeed), @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"retimeSetInterpolation"]) {
                // Set interpolation type on retime segments
                id selectedItems = getSelectedItems();
                NSString *interpolation = params[@"interpolation"];
                SEL sel = NSSelectorFromString(@"actionRetimeSetInterpolation:edits:");
                ((void (*)(id, SEL, id, id))objc_msgSend)(timeline, sel, interpolation, selectedItems);
                result = @{@"action": action, @"status": @"ok"};
                return;
            }

            // === Trim / Edit (Direct API) ===
            // More precise than the IBAction trim commands, which are mode-dependent
            // and coarse. These take explicit parameters and return errors properly.

            if ([action isEqualToString:@"splitAtTime"]) {
                // Blade/split at exact time on a specific clip or all clips
                // This is more precise than the responder-chain blade
                double time = [params[@"time"] doubleValue];
                int64_t timeValue = (int64_t)(time * 600);
                SEL makeSel = NSSelectorFromString(@"CMTimeMake::");
                id cmtime = nil; // We'll use the Flexo time APIs
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionSplitItems:atTime:forContainer:error:");
                ((void (*)(id, SEL, id, id, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, nil, rootItem, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"trimDuration"]) {
                // Trim selected edits to a specific duration
                BOOL isDelta = params[@"isDelta"] ? [params[@"isDelta"] boolValue] : NO;
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionTrimDuration:forEdits:isDelta:error:");
                ((void (*)(id, SEL, id, id, BOOL, NSError **))objc_msgSend)(
                    timeline, sel, nil, selectedItems, isDelta, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"extendOverNextClip"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionExtendOverNextClip:error:");
                ((void (*)(id, SEL, id, NSError **))objc_msgSend)(timeline, sel, selectedItems, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"joinThroughEdits"]) {
                BOOL onEdges = params[@"onEdges"] ? [params[@"onEdges"] boolValue] : YES;
                BOOL onLeft = params[@"onLeft"] ? [params[@"onLeft"] boolValue] : YES;
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionJoinThroughEdits:onEdges:onLeft:error:");
                ((void (*)(id, SEL, id, BOOL, BOOL, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, onEdges, onLeft, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"removeEdits"]) {
                BOOL replaceWithGap = params[@"replaceWithGap"] ? [params[@"replaceWithGap"] boolValue] : NO;
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionRemoveEdits:replaceWithGap:removeOperation:rootItem:error:");
                ((void (*)(id, SEL, id, BOOL, int, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, replaceWithGap, 0, rootItem, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"replaceWithGap": @(replaceWithGap), @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"insertGapDirect"]) {
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionInsertGap:rootItem:error:");
                ((void (*)(id, SEL, id, id, NSError **))objc_msgSend)(timeline, sel, nil, rootItem, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"insertFreezeFrame"]) {
                // Programmatic freeze frame insertion at playhead
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionInsertFreezeFrameAtTime:rootItem:toItems:endTime:error:");
                ((void (*)(id, SEL, id, id, id, id, NSError **))objc_msgSend)(
                    timeline, sel, nil, rootItem, selectedItems, nil, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            // === Nudge (Direct API with amounts) ===

            if ([action isEqualToString:@"nudgeAnchoredItems"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionNudgeAnchoredItems:rootItem:nudgeAmount:error:");
                ((void (*)(id, SEL, id, id, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, rootItem, nil, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"nudgeSpineItems"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionNudgeSpineItems:rootItem:nudgeAmount:error:");
                ((void (*)(id, SEL, id, id, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, rootItem, nil, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            // === Audio Operations ===
            // Direct audio manipulation — volume (absolute or relative dB), fades,
            // background music flag, audio detach, and A/V sync alignment.

            if ([action isEqualToString:@"changeAudioVolume"]) {
                double amount = [params[@"amount"] doubleValue];
                BOOL isRelative = params[@"relative"] ? [params[@"relative"] boolValue] : YES;
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionChangeAudioVolume:byAmount:overRange:isRelative:error:");
                ((void (*)(id, SEL, id, double, id, BOOL, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, amount, nil, isRelative, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"amount": @(amount), @"relative": @(isRelative), @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"applyAudioFadesDirect"]) {
                BOOL fadeIn = params[@"fadeIn"] ? [params[@"fadeIn"] boolValue] : YES;
                double duration = params[@"duration"] ? [params[@"duration"] doubleValue] : 0.5;
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionApplyAudioFades:objects:fadeInNotOut:fadeDuration:error:");
                ((void (*)(id, SEL, id, id, BOOL, double, NSError **))objc_msgSend)(
                    timeline, sel, nil, selectedItems, fadeIn, duration, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"fadeIn": @(fadeIn), @"duration": @(duration), @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"setAudioPlayEnable"]) {
                BOOL enabled = params[@"enabled"] ? [params[@"enabled"] boolValue] : YES;
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionSetAudioPlayEnable:error:");
                ((void (*)(id, SEL, BOOL, NSError **))objc_msgSend)(timeline, sel, enabled, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"enabled": @(enabled), @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"setBackgroundMusic"]) {
                BOOL isBackground = params[@"enabled"] ? [params[@"enabled"] boolValue] : YES;
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionSetBackgroundMusic:isBackgroundMusic:error:");
                ((void (*)(id, SEL, id, BOOL, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, isBackground, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"enabled": @(isBackground), @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"detachAudioDirect"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionDetachAudio:newDetachedEdits:error:");
                ((void (*)(id, SEL, id, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, nil, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"alignAudioToVideoDirect"]) {
                id selectedItems = getSelectedItems();
                SEL sel = NSSelectorFromString(@"actionAlignAudioToVideo:endEdits:container:");
                ((void (*)(id, SEL, id, id, id))objc_msgSend)(
                    timeline, sel, selectedItems, nil, rootItem);
                result = @{@"action": action, @"status": @"ok"};
                return;
            }

            // === Multicam / Angles ===
            // FCP's multicam clips have "angles" that can be renamed, deleted,
            // or audio-synced independently.

            if ([action isEqualToString:@"deleteMultiAngle"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionDeleteMultiAngle:error:");
                ((void (*)(id, SEL, id, NSError **))objc_msgSend)(timeline, sel, selectedItems, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"renameAngle"]) {
                NSString *newName = params[@"name"];
                if (!newName) { result = @{@"error": @"name parameter required"}; return; }
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionRenameAngle:newName:error:");
                ((void (*)(id, SEL, id, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, newName, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"name": newName, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"audioSyncMultiAngle"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionAudioSyncMultiAngleItems:rootItem:error:");
                ((void (*)(id, SEL, id, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, rootItem, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            // === Keywords / Roles ===
            // Keywords are FCP's tagging system. Roles control audio/video routing
            // for export (Dialogue, Music, Effects, Titles, etc).

            if ([action isEqualToString:@"addKeywords"]) {
                NSArray *keywords = params[@"keywords"];
                if (!keywords) { result = @{@"error": @"keywords array required"}; return; }
                NSSet *keywordSet = [NSSet setWithArray:keywords];
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionAddKeywordsWithNames:forRange:animationHint:error:");
                ((void (*)(id, SEL, id, id, int, NSError **))objc_msgSend)(
                    timeline, sel, keywordSet, nil, 0, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"keywords": keywords, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"removeKeywords"]) {
                NSArray *keywords = params[@"keywords"];
                if (!keywords) { result = @{@"error": @"keywords array required"}; return; }
                NSSet *keywordSet = [NSSet setWithArray:keywords];
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionRemoveKeywordsWithNames:error:");
                ((void (*)(id, SEL, id, NSError **))objc_msgSend)(timeline, sel, keywordSet, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"setRole"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionSetRole:error:");
                ((void (*)(id, SEL, id, NSError **))objc_msgSend)(timeline, sel, selectedItems, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            // === Effects / Masks ===
            // Manipulate effects on selected clips: remove by ID, invert masks,
            // toggle enabled state.

            if ([action isEqualToString:@"removeEffectByID"]) {
                NSString *effectID = params[@"effectID"];
                if (!effectID) { result = @{@"error": @"effectID parameter required"}; return; }
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionRemoveEffectID:fromAnchoredObjects:error:");
                ((void (*)(id, SEL, id, id, NSError **))objc_msgSend)(
                    timeline, sel, effectID, selectedItems, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"effectID": effectID, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"invertEffectMasks"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionInvertEffectMasks:actionName:error:");
                ((void (*)(id, SEL, id, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, @"Invert Mask", &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"toggleEnabled"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionToggleEnabled:error:");
                ((void (*)(id, SEL, id, NSError **))objc_msgSend)(timeline, sel, selectedItems, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            // === Clip Operations ===
            // Structural operations on clips: break apart compound clips, create new
            // compound clips, lift from storyline, rename, delete, move to trash.

            if ([action isEqualToString:@"breakApartClipItems"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionBreakApartClipItems:error:");
                ((void (*)(id, SEL, id, NSError **))objc_msgSend)(timeline, sel, selectedItems, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"createCompoundClipDirect"]) {
                BOOL multiClip = [params[@"multicam"] boolValue];
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionCreateCompoundClip:multiClip:spine:error:");
                ((void (*)(id, SEL, id, BOOL, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, multiClip, nil, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"multicam": @(multiClip), @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"liftAnchoredEdits"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionLiftAnchoredEdits:rootItem:error:");
                ((void (*)(id, SEL, id, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, rootItem, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"renameDirect"]) {
                NSString *newName = params[@"name"];
                if (!newName) { result = @{@"error": @"name parameter required"}; return; }
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionRename:actionName:error:");
                ((void (*)(id, SEL, id, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, newName, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"name": newName, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"deleteItemsInArray"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionDeleteItemsInArray:error:");
                ((void (*)(id, SEL, id, NSError **))objc_msgSend)(timeline, sel, selectedItems, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"moveClipsToTrash"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionMoveClipsToTrash:mediaRefsToDelete:error:");
                ((void (*)(id, SEL, id, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, nil, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            // === Captions ===
            // Duplicate captions to a different language/format for localization.

            if ([action isEqualToString:@"duplicateCaptions"]) {
                NSString *language = params[@"language"] ?: @"en";
                NSString *format = params[@"format"] ?: @"ITT";
                id selectedItems = getSelectedItems();
                SEL sel = NSSelectorFromString(@"actionDuplicateCaptions:toLanguageIdentifier:andCaptionFormat:");
                ((void (*)(id, SEL, id, id, id))objc_msgSend)(
                    timeline, sel, selectedItems, language, format);
                result = @{@"action": action, @"language": language, @"format": format, @"status": @"ok"};
                return;
            }

            // === Audition / Variants ===
            // Auditions let you stack multiple takes in one timeline slot and cycle
            // through them. "Variants" are the individual takes within an audition.

            if ([action isEqualToString:@"addVariants"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionAddVariants:error:");
                ((void (*)(id, SEL, id, NSError **))objc_msgSend)(timeline, sel, selectedItems, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"removeVariants"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionRemoveVariants:error:");
                ((void (*)(id, SEL, id, NSError **))objc_msgSend)(timeline, sel, selectedItems, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"finalizeVariant"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionFinalizePickFromVariant:rootItem:error:");
                ((void (*)(id, SEL, id, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, rootItem, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            // === Project / Library ===

            if ([action isEqualToString:@"newProject"]) {
                NSString *name = params[@"name"] ?: @"Untitled";
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionNewProject:name:sequence:actionName:error:");
                ((void (*)(id, SEL, id, id, id, id, NSError **))objc_msgSend)(
                    timeline, sel, nil, name, nil, @"New Project", &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"name": name, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"newEvent"]) {
                NSString *name = params[@"name"] ?: @"New Event";
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionNewEvent:name:actionName:error:");
                ((void (*)(id, SEL, id, id, id, NSError **))objc_msgSend)(
                    timeline, sel, nil, name, @"New Event", &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"name": name, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"validateAndRepair"]) {
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionValidateAndRepair:validateMode:error:");
                ((void (*)(id, SEL, id, int, NSError **))objc_msgSend)(
                    timeline, sel, nil, 0, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            // === Auto-reframe (Direct) ===

            if ([action isEqualToString:@"autoReframeDirect"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionAutoReframe:forContainer:error:");
                ((void (*)(id, SEL, id, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, rootItem, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            // === Music alignment ===

            if ([action isEqualToString:@"alignToMusicMarkers"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionAlignToMusicMarkers:rootItem:error:");
                ((void (*)(id, SEL, id, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, rootItem, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"alignClipsAtMusicMarkers"]) {
                BOOL asSplit = [params[@"asSplit"] boolValue];
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionAlignClipsAtMusicMarkersOnItems:rootItem:asSplit:error:");
                ((void (*)(id, SEL, id, id, BOOL, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, rootItem, asSplit, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"asSplit": @(asSplit), @"status": @"ok"};
                return;
            }

            // === Transition operations (Direct) ===

            if ([action isEqualToString:@"addTransitionsDirect"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionAddTransitionsToSpineObjects:before:after:effects:transitionOverlapType:transitionsCreated:rootItem:reportErrors:error:");
                ((void (*)(id, SEL, id, id, id, id, int, id, id, BOOL, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, nil, nil, nil, 0, nil, rootItem, YES, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            // === Analyze and optimize ===

            if ([action isEqualToString:@"analyzeAndOptimize"]) {
                id selectedItems = getSelectedItems();
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionPerformAnalyzeAndOptimizeClips:options:error:");
                ((void (*)(id, SEL, id, id, NSError **))objc_msgSend)(
                    timeline, sel, selectedItems, nil, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            // === Lane conflict resolution ===

            if ([action isEqualToString:@"resolveLaneConflicts"]) {
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionResolveLaneConflictsInContainer:excludedItems:error:");
                ((void (*)(id, SEL, id, id, NSError **))objc_msgSend)(
                    timeline, sel, rootItem, nil, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            if ([action isEqualToString:@"resolveLaneGaps"]) {
                NSError *error = nil;
                SEL sel = NSSelectorFromString(@"actionResolveLaneGapsInContainer:error:");
                ((void (*)(id, SEL, id, NSError **))objc_msgSend)(timeline, sel, rootItem, &error);
                result = error ? @{@"error": error.localizedDescription}
                               : @{@"action": action, @"status": @"ok"};
                return;
            }

            // === Fallback: raw selector invocation ===
            // If a selector string is provided directly, try to call it on the timeline module
            if (rawSelector) {
                SEL sel = NSSelectorFromString(rawSelector);
                if (![timeline respondsToSelector:sel]) {
                    result = @{@"error": [NSString stringWithFormat:@"Timeline module does not respond to %@", rawSelector]};
                    return;
                }
                // Count colons to determine argument count
                NSUInteger colonCount = [[rawSelector componentsSeparatedByString:@":"] count] - 1;
                if (colonCount == 0) {
                    ((void (*)(id, SEL))objc_msgSend)(timeline, sel);
                } else if (colonCount == 1) {
                    ((void (*)(id, SEL, id))objc_msgSend)(timeline, sel, nil);
                } else if (colonCount == 2) {
                    NSError *error = nil;
                    ((void (*)(id, SEL, id, NSError **))objc_msgSend)(timeline, sel, nil, &error);
                    if (error) { result = @{@"error": error.localizedDescription}; return; }
                } else {
                    // For 3+ args, pass nils - caller should use call_method for full control
                    ((void (*)(id, SEL, id, id, id))objc_msgSend)(timeline, sel, nil, nil, nil);
                }
                result = @{@"selector": rawSelector, @"status": @"ok"};
                return;
            }

            result = @{@"error": [NSString stringWithFormat:@"Unknown direct action: %@", action]};
        } @catch (NSException *e) {
            result = @{@"error": [NSString stringWithFormat:@"Exception: %@", e.reason]};
        }
    });

    return result;
}

static id SpliceKit_getAppDelegate(void) {
    id app = ((id (*)(id, SEL))objc_msgSend)(
        objc_getClass("NSApplication"), @selector(sharedApplication));
    return app ? ((id (*)(id, SEL))objc_msgSend)(app, @selector(delegate)) : nil;
}

static id SpliceKit_getCompareViewerContainer(void) {
    id delegate = SpliceKit_getAppDelegate();
    SEL compareSel = NSSelectorFromString(@"compareViewer");
    if (delegate && [delegate respondsToSelector:compareSel]) {
        id viewer = ((id (*)(id, SEL))objc_msgSend)(delegate, compareSel);
        if (viewer) return viewer;
    }
    return nil;
}

static id SpliceKit_getContextFromPlayerContainer(id container) {
    if (!container) return nil;

    SEL contextSel = NSSelectorFromString(@"context");
    if ([container respondsToSelector:contextSel]) {
        id context = ((id (*)(id, SEL))objc_msgSend)(container, contextSel);
        if (context) return context;
    }

    for (NSString *playerSelName in @[@"viewerPlayerModule", @"canvasPlayerModule", @"_activePlayerModule"]) {
        SEL playerSel = NSSelectorFromString(playerSelName);
        if (![container respondsToSelector:playerSel]) continue;

        id playerModule = ((id (*)(id, SEL))objc_msgSend)(container, playerSel);
        if (!playerModule) continue;
        if (![playerModule respondsToSelector:contextSel]) continue;

        id context = ((id (*)(id, SEL))objc_msgSend)(playerModule, contextSel);
        if (context) return context;
    }

    return nil;
}

static id SpliceKit_getPlayerModuleFromPlayerContainer(id container) {
    if (!container) return nil;

    for (NSString *selName in @[@"viewerPlayerModule", @"canvasPlayerModule", @"_activePlayerModule"]) {
        SEL sel = NSSelectorFromString(selName);
        if (![container respondsToSelector:sel]) continue;

        id playerModule = ((id (*)(id, SEL))objc_msgSend)(container, sel);
        if (playerModule) return playerModule;
    }

    SEL modulesSel = NSSelectorFromString(@"playerModules");
    if ([container respondsToSelector:modulesSel]) {
        id modules = ((id (*)(id, SEL))objc_msgSend)(container, modulesSel);
        SEL firstSel = NSSelectorFromString(@"firstObject");
        if (modules && [modules respondsToSelector:firstSel]) {
            id firstPlayerModule = ((id (*)(id, SEL))objc_msgSend)(modules, firstSel);
            if (firstPlayerModule) return firstPlayerModule;
        }
    }

    return nil;
}

// Get the FFPlayerModule from editor container
static id SpliceKit_getPlayerModule(void) {
    id container = SpliceKit_getEditorContainer();

    // Try playerModule or editorModule.playerModule
    SEL pmSel = NSSelectorFromString(@"playerModule");
    if (container && [container respondsToSelector:pmSel]) {
        return ((id (*)(id, SEL))objc_msgSend)(container, pmSel);
    }
    // Try through editorModule
    SEL emSel = NSSelectorFromString(@"editorModule");
    if (container && [container respondsToSelector:emSel]) {
        id editor = ((id (*)(id, SEL))objc_msgSend)(container, emSel);
        if (editor && [editor respondsToSelector:pmSel]) {
            return ((id (*)(id, SEL))objc_msgSend)(editor, pmSel);
        }
    }

    id compareViewer = SpliceKit_getCompareViewerContainer();
    id compareViewerPlayer = SpliceKit_getPlayerModuleFromPlayerContainer(compareViewer);
    if (compareViewerPlayer) return compareViewerPlayer;

    return nil;
}

// Resolve the playback context used by the active timeline/player.
id SpliceKit_getPlaybackContext(void) {
    id timeline = SpliceKit_getActiveTimelineModule();
    SEL contextSel = NSSelectorFromString(@"context");
    if (timeline && [timeline respondsToSelector:contextSel]) {
        id context = ((id (*)(id, SEL))objc_msgSend)(timeline, contextSel);
        if (context) return context;
    }

    SEL selectionContextSel = NSSelectorFromString(@"selectionContext");
    if (timeline && [timeline respondsToSelector:selectionContextSel]) {
        id context = ((id (*)(id, SEL))objc_msgSend)(timeline, selectionContextSel);
        if (context) return context;
    }

    id playerModule = SpliceKit_getPlayerModule();
    if (playerModule && [playerModule respondsToSelector:contextSel]) {
        id context = ((id (*)(id, SEL))objc_msgSend)(playerModule, contextSel);
        if (context) return context;
    }

    id compareViewer = SpliceKit_getCompareViewerContainer();
    id compareViewerContext = SpliceKit_getContextFromPlayerContainer(compareViewer);
    if (compareViewerContext) return compareViewerContext;

    return nil;
}

static id SpliceKit_getAudioDestFromContext(id context) {
    if (!context) return nil;

    SEL audioDestSel = NSSelectorFromString(@"audioDest");
    if ([context respondsToSelector:audioDestSel]) {
        id audioDest = ((id (*)(id, SEL))objc_msgSend)(context, audioDestSel);
        if (audioDest) return audioDest;
    }

    Ivar ivar = class_getInstanceVariable([context class], "_audioDest");
    if (ivar) {
        id audioDest = object_getIvar(context, ivar);
        if (audioDest) return audioDest;
    }

    @try {
        id audioDest = [context valueForKey:@"audioDest"];
        if (audioDest) return audioDest;
    } @catch (NSException *e) {}

    return nil;
}

// The playback context owns the program-output audio destination.
id SpliceKit_getMasterAudioDest(void) {
    id timeline = SpliceKit_getActiveTimelineModule();
    SEL contextSel = NSSelectorFromString(@"context");
    if (timeline && [timeline respondsToSelector:contextSel]) {
        id context = ((id (*)(id, SEL))objc_msgSend)(timeline, contextSel);
        id audioDest = SpliceKit_getAudioDestFromContext(context);
        if (audioDest) return audioDest;
    }

    SEL selectionContextSel = NSSelectorFromString(@"selectionContext");
    if (timeline && [timeline respondsToSelector:selectionContextSel]) {
        id context = ((id (*)(id, SEL))objc_msgSend)(timeline, selectionContextSel);
        id audioDest = SpliceKit_getAudioDestFromContext(context);
        if (audioDest) return audioDest;
    }

    id playerModule = SpliceKit_getPlayerModule();
    if (playerModule && [playerModule respondsToSelector:contextSel]) {
        id context = ((id (*)(id, SEL))objc_msgSend)(playerModule, contextSel);
        id audioDest = SpliceKit_getAudioDestFromContext(context);
        if (audioDest) return audioDest;
    }

    id compareViewer = SpliceKit_getCompareViewerContainer();
    id compareViewerContext = SpliceKit_getContextFromPlayerContainer(compareViewer);
    id compareViewerAudioDest = SpliceKit_getAudioDestFromContext(compareViewerContext);
    if (compareViewerAudioDest) return compareViewerAudioDest;

    id fallbackContext = SpliceKit_getPlaybackContext();
    id fallbackAudioDest = SpliceKit_getAudioDestFromContext(fallbackContext);
    if (fallbackAudioDest) return fallbackAudioDest;

    return nil;
}

// Send action via NSApp.sendAction:to:from: (goes through responder chain)
static NSDictionary *SpliceKit_sendAppAction(NSString *selectorName) {
    __block NSDictionary *result = nil;

    SpliceKit_executeOnMainThread(^{
        @try {
            id app = ((id (*)(id, SEL))objc_msgSend)(
                objc_getClass("NSApplication"), @selector(sharedApplication));
            SEL sel = NSSelectorFromString(selectorName);
            BOOL sent = ((BOOL (*)(id, SEL, SEL, id, id))objc_msgSend)(
                app, @selector(sendAction:to:from:), sel, nil, nil);
            if (sent) {
                result = @{@"action": selectorName, @"status": @"ok"};
            } else {
                result = @{@"error": [NSString stringWithFormat:
                    @"No responder handled %@", selectorName]};
            }
        } @catch (NSException *e) {
            result = @{@"error": [NSString stringWithFormat:@"Exception: %@", e.reason]};
        }
    });

    return result;
}

// Send action to the player module specifically
static NSDictionary *SpliceKit_sendPlayerAction(NSString *selectorName) {
    __block NSDictionary *result = nil;

    SpliceKit_executeOnMainThread(^{
        @try {
            id player = SpliceKit_getPlayerModule();
            if (!player) {
                result = @{@"error": @"No player module found"};
                return;
            }

            SEL sel = NSSelectorFromString(selectorName);
            if (![player respondsToSelector:sel]) {
                result = @{@"error": [NSString stringWithFormat:
                    @"Player module does not respond to %@", selectorName]};
                return;
            }

            ((void (*)(id, SEL, id))objc_msgSend)(player, sel, nil);
            result = @{@"action": selectorName, @"status": @"ok"};
        } @catch (NSException *e) {
            result = @{@"error": [NSString stringWithFormat:@"Exception: %@", e.reason]};
        }
    });

    return result;
}

NSDictionary *SpliceKit_handlePlayback(NSDictionary *params) {
    NSString *action = params[@"action"];
    if (!action) return @{@"error": @"action parameter required"};

    // All playback actions go through the responder chain (NSApp.sendAction:to:from:)
    // This is how FCP's menu items work - they route to FFPlayerModule,
    // PEEditorContainerModule, etc. automatically.
    NSDictionary *actionMap = @{
        @"playPause":         @"playPause:",
        @"goToStart":         @"gotoStart:",
        @"goToEnd":           @"gotoEnd:",
        @"nextFrame":         @"stepForward:",
        @"prevFrame":         @"stepBackward:",
        @"nextFrame10":       @"stepForward10Frames:",
        @"prevFrame10":       @"stepBackward10Frames:",
        @"playAroundCurrent": @"playAroundCurrentFrame:",
        @"playFromStart":    @"playFromStart:",
        @"playInToOut":      @"playInToOut:",
        @"playReverse":      @"playReverse:",
        @"stopPlaying":      @"stopPlaying:",
        @"loop":             @"loop:",
        @"fastForward":      @"fastForward:",
        @"rewind":           @"rewind:",
        // Named rate presets (JKL-style)
        @"playRate1X":        @"playRate1X:",
        @"playRate2X":        @"playRate2X:",
        @"playRate4X":        @"playRate4X:",
        @"playRate8X":        @"playRate8X:",
        @"playRate16X":       @"playRate16X:",
        @"playRate32X":       @"playRate32X:",
        @"playRateHalf":      @"playRateHalf:",
        @"playRateMinusHalf": @"playRateMinusHalf:",
        @"playRateMinus1X":   @"playRateMinus1X:",
        @"playRateMinus2X":   @"playRateMinus2X:",
        @"playRateMinus32X":  @"playRateMinus32X:",
    };

    NSString *selector = actionMap[action];
    if (!selector) {
        selector = action;
        if (![selector hasSuffix:@":"]) {
            selector = [selector stringByAppendingString:@":"];
        }
    }

    return SpliceKit_sendAppAction(selector);
}

NSDictionary *SpliceKit_handlePlaybackSeek(NSDictionary *params) {
    NSNumber *seconds = params[@"seconds"];
    if (!seconds) return @{@"error": @"seconds parameter required"};

    __block NSDictionary *result = nil;
    SpliceKit_executeOnMainThread(^{
        @try {
            id timeline = SpliceKit_getActiveTimelineModule();
            if (!timeline) {
                result = @{@"error": @"No active timeline module"};
                return;
            }

            // Get the sequence timescale for accurate time construction
            int32_t timescale = 24000; // default
            SEL seqSel = @selector(sequence);
            if ([timeline respondsToSelector:seqSel]) {
                id sequence = ((id (*)(id, SEL))objc_msgSend)(timeline, seqSel);
                if (sequence) {
                    // Try to get frameDuration to derive timescale
                    // On ARM64, objc_msgSend handles struct returns directly
                    SEL fdSel = NSSelectorFromString(@"frameDuration");
                    if ([sequence respondsToSelector:fdSel]) {
                        SpliceKit_CMTime fd = ((SpliceKit_CMTime (*)(id, SEL))STRET_MSG)(
                            sequence, fdSel);
                        if (fd.timescale > 0) timescale = fd.timescale;
                    }
                }
            }

            // Build CMTime from seconds
            double secs = [seconds doubleValue];
            SpliceKit_CMTime targetTime;
            targetTime.value = (int64_t)(secs * timescale);
            targetTime.timescale = timescale;
            targetTime.flags = 1; // kCMTimeFlags_Valid
            targetTime.epoch = 0;

            // Call setPlayheadTime: on the timeline module
            SEL setSel = @selector(setPlayheadTime:);
            if ([timeline respondsToSelector:setSel]) {
                ((void (*)(id, SEL, SpliceKit_CMTime))objc_msgSend)(
                    timeline, setSel, targetTime);
                result = @{
                    @"status": @"ok",
                    @"seconds": @(secs),
                    @"time": SpliceKit_serializeCMTime(targetTime),
                };
            } else {
                result = @{@"error": @"Timeline module does not respond to setPlayheadTime:"};
            }
        } @catch (NSException *e) {
            result = @{@"error": [NSString stringWithFormat:@"Exception: %@", e.reason]};
        }
    });
    return result ?: @{@"error": @"Failed to seek"};
}

NSDictionary *SpliceKit_handlePlaybackGetPosition(NSDictionary *params) {
    __block NSDictionary *result = nil;
    SpliceKit_executeOnMainThread(^{
        @try {
            id timeline = SpliceKit_getActiveTimelineModule();
            if (!timeline) { result = @{@"error": @"No active timeline module"}; return; }

            // Read playhead time
            SEL phSel = NSSelectorFromString(@"playheadTime");
            if ([timeline respondsToSelector:phSel]) {
                SpliceKit_CMTime pht = ((SpliceKit_CMTime (*)(id, SEL))STRET_MSG)(timeline, phSel);
                double seconds = (pht.timescale > 0) ? (double)pht.value / pht.timescale : 0;

                NSMutableDictionary *r = [NSMutableDictionary dictionary];
                r[@"seconds"] = @(seconds);
                r[@"time"] = SpliceKit_serializeCMTime(pht);

                // Also get sequence duration for context
                SEL seqSel = @selector(sequence);
                if ([timeline respondsToSelector:seqSel]) {
                    id sequence = ((id (*)(id, SEL))objc_msgSend)(timeline, seqSel);
                    if (sequence && [sequence respondsToSelector:@selector(duration)]) {
                        SpliceKit_CMTime dur = ((SpliceKit_CMTime (*)(id, SEL))STRET_MSG)(sequence, @selector(duration));
                        r[@"duration"] = SpliceKit_serializeCMTime(dur);
                    }
                    // Frame rate
                    SEL fdSel = NSSelectorFromString(@"frameDuration");
                    if (sequence && [sequence respondsToSelector:fdSel]) {
                        SpliceKit_CMTime fd = ((SpliceKit_CMTime (*)(id, SEL))STRET_MSG)(sequence, fdSel);
                        if (fd.timescale > 0 && fd.value > 0) {
                            r[@"frameRate"] = @((double)fd.timescale / fd.value);
                            r[@"frameDuration"] = SpliceKit_serializeCMTime(fd);
                        }
                    }
                }

                // Check if playing
                SEL playSel = NSSelectorFromString(@"isPlaying");
                if ([timeline respondsToSelector:playSel]) {
                    BOOL playing = ((BOOL (*)(id, SEL))objc_msgSend)(timeline, playSel);
                    r[@"isPlaying"] = @(playing);
                }

                // Read current playback rate from player
                // Try timeline -> player -> rate (FFPlayerModule path)
                SEL playerSel = NSSelectorFromString(@"player");
                id player = nil;
                // First try getting player from timeline module
                if ([timeline respondsToSelector:playerSel]) {
                    player = ((id (*)(id, SEL))objc_msgSend)(timeline, playerSel);
                }
                // Fallback: try FFPlayerModule from editor container
                if (!player) {
                    id pm = SpliceKit_getPlayerModule();
                    if (pm && [pm respondsToSelector:playerSel]) {
                        player = ((id (*)(id, SEL))objc_msgSend)(pm, playerSel);
                    }
                }
                if (player) {
                    SEL rateSel = NSSelectorFromString(@"rate");
                    if ([player respondsToSelector:rateSel]) {
                        double currentRate = ((double (*)(id, SEL))objc_msgSend)(player, rateSel);
                        r[@"rate"] = @(currentRate);
                    }
                }

                result = r;
            } else {
                result = @{@"error": @"Cannot read playhead time"};
            }
        } @catch (NSException *e) {
            result = @{@"error": [NSString stringWithFormat:@"Exception: %@", e.reason]};
        }
    });
    return result ?: @{@"error": @"Failed to get position"};
}

#pragma mark - Playback Speed Configuration

static NSString * const kSpliceKitLLadder = @"SpliceKitLLadder";
static NSString * const kSpliceKitJLadder = @"SpliceKitJLadder";

NSArray<NSNumber *> *SpliceKit_getLLadder(void) {
    NSArray *stored = [[NSUserDefaults standardUserDefaults] arrayForKey:kSpliceKitLLadder];
    if (stored.count > 0) return stored;
    return @[@1, @2, @4, @8, @16, @32];
}

void SpliceKit_setLLadder(NSArray<NSNumber *> *speeds) {
    [[NSUserDefaults standardUserDefaults] setObject:speeds forKey:kSpliceKitLLadder];
    SpliceKit_log(@"[Speed] L ladder set to: %@", speeds);
}

NSArray<NSNumber *> *SpliceKit_getJLadder(void) {
    NSArray *stored = [[NSUserDefaults standardUserDefaults] arrayForKey:kSpliceKitJLadder];
    if (stored.count > 0) return stored;
    return @[@1, @2, @4, @8, @16, @32];
}

void SpliceKit_setJLadder(NSArray<NSNumber *> *speeds) {
    [[NSUserDefaults standardUserDefaults] setObject:speeds forKey:kSpliceKitJLadder];
    SpliceKit_log(@"[Speed] J ladder set to: %@", speeds);
}

// Helper to set playback rate via responder chain (always works)
void SpliceKit_setPlaybackRate(float rate) {
    SpliceKit_executeOnMainThread(^{
        // playRate selectors go through the responder chain and route to FFPlayerModule
        NSDictionary *rateSelectors = @{
            @(0.5f): @"playRateHalf:", @(1.0f): @"playRate1X:",
            @(2.0f): @"playRate2X:", @(4.0f): @"playRate4X:",
            @(8.0f): @"playRate8X:", @(16.0f): @"playRate16X:",
            @(32.0f): @"playRate32X:", @(-1.0f): @"playRateMinus1X:",
            @(-2.0f): @"playRateMinus2X:", @(-32.0f): @"playRateMinus32X:",
        };
        NSString *sel = rateSelectors[@(rate)];
        if (sel) {
            SpliceKit_sendAppAction(sel);
        } else {
            // For non-standard rates, use fastForward/rewind which will use our swizzled ladder
            // Or try direct _playWithRate: on player module
            id playerModule = SpliceKit_getPlayerModule();
            if (playerModule) {
                SEL pwrSel = NSSelectorFromString(@"_playWithRate:");
                if ([playerModule respondsToSelector:pwrSel]) {
                    ((void (*)(id, SEL, float))objc_msgSend)(playerModule, pwrSel, rate);
                    return;
                }
            }
            // Last resort: closest standard rate
            float best = 1.0f;
            float bestDist = HUGE_VALF;
            for (NSNumber *key in rateSelectors) {
                float dist = fabsf([key floatValue] - rate);
                if (dist < bestDist) { bestDist = dist; best = [key floatValue]; }
            }
            SpliceKit_sendAppAction(rateSelectors[@(best)]);
        }
    });
}

NSDictionary *SpliceKit_handlePlaybackSetRate(NSDictionary *params) {
    NSNumber *rateNum = params[@"rate"];
    if (!rateNum) return @{@"error": @"rate parameter required"};
    float rate = [rateNum floatValue];
    SpliceKit_setPlaybackRate(rate);
    return @{@"status": @"ok", @"requestedRate": @(rate)};
}

NSDictionary *SpliceKit_handlePlaybackShuttle(NSDictionary *params) {
    NSString *direction = params[@"direction"];
    if (!direction) return @{@"error": @"direction parameter required (faster/slower/stop)"};
    if ([direction isEqualToString:@"stop"]) return SpliceKit_sendAppAction(@"stopPlaying:");
    // Just trigger the (swizzled) fastForward/rewind via responder chain
    if ([direction isEqualToString:@"faster"]) return SpliceKit_sendAppAction(@"fastForward:");
    return SpliceKit_sendAppAction(@"rewind:");
}

#pragma mark - Playback Speed Swizzle (J/L ladder)
//
// Swizzle fastForward: and rewind: on FFPlayerModule to use configurable speed
// ladders instead of the hardcoded 1→2→4→8→16→32 progression.
//
// The original logic: get current rate, find next power-of-two up/down, call _playWithRate:.
// Our replacement: same structure, but walk our configurable array instead.
//

static IMP sOrigFastForward = NULL;
static IMP sOrigRewind = NULL;

// Read a BOOL ivar from an object by name
static BOOL SpliceKit_readBoolIvar(id obj, const char *name) {
    Ivar ivar = class_getInstanceVariable(object_getClass(obj), name);
    if (!ivar) return NO;
    return *(BOOL *)((uint8_t *)(__bridge void *)obj + ivar_getOffset(ivar));
}

// Given a sorted ascending ladder and a current rate, find the next step up.
// Returns the first ladder value strictly greater than currentRate.
// If currentRate >= max, returns max (stay at top).
static float SpliceKit_nextLadderUp(NSArray<NSNumber *> *ladder, double currentRate) {
    for (NSNumber *speed in ladder) {
        if ([speed floatValue] > currentRate + 0.01f) return [speed floatValue];
    }
    return [ladder.lastObject floatValue];
}

// Given a sorted ascending ladder and a current rate (negative), find the next step down.
// ladder is stored positive, currentRate is negative.
// Returns the next more-negative value.
static float SpliceKit_nextLadderDown(NSArray<NSNumber *> *ladder, double currentRate) {
    // currentRate is negative (e.g. -2.0). Walk ladder to find next bigger absolute value.
    double absRate = fabs(currentRate);
    for (NSNumber *speed in ladder) {
        if ([speed floatValue] > absRate + 0.01f) return -[speed floatValue];
    }
    return -[ladder.lastObject floatValue];
}

static void SpliceKit_swizzled_fastForward(id self, SEL _cmd, id sender) {
    // Replicate K+L = step forward, and key-repeat filtering
    BOOL stopIsDown = SpliceKit_readBoolIvar(self, "_stopPlayingIsDown");

    if ([sender respondsToSelector:@selector(repeatCount)]) {
        NSInteger rc = ((NSInteger (*)(id, SEL))objc_msgSend)(sender, @selector(repeatCount));
        if (stopIsDown) {
            ((void (*)(id, SEL, id))objc_msgSend)(self, @selector(stepForward:), sender);
            return;
        }
        if (rc > 0) return; // ignore key repeats
    } else if (stopIsDown) {
        ((void (*)(id, SEL, id))objc_msgSend)(self, @selector(stepForward:), sender);
        return;
    }

    // End any step playback
    SEL endStepSel = NSSelectorFromString(@"_endStepPlayback");
    if ([self respondsToSelector:endStepSel])
        ((void (*)(id, SEL))objc_msgSend)(self, endStepSel);

    // Get current rate from FFPlayer
    double currentRate = 0.0;
    SEL playerSel = @selector(player);
    if ([self respondsToSelector:playerSel]) {
        id player = ((id (*)(id, SEL))objc_msgSend)(self, playerSel);
        if (player) {
            SEL rateSel = NSSelectorFromString(@"rate");
            if ([player respondsToSelector:rateSel])
                currentRate = ((double (*)(id, SEL))objc_msgSend)(player, rateSel);
        }
    }

    // Set loop range if not currently playing (required for playback to start)
    SEL isPlayingSel = NSSelectorFromString(@"isPlaying");
    BOOL playing = [self respondsToSelector:isPlayingSel]
        ? ((BOOL (*)(id, SEL))objc_msgSend)(self, isPlayingSel) : NO;
    if (!playing) {
        // Call original just for loop range setup, then override rate
        // Actually — just call playAtTime:rate: which _playWithRate: does internally.
        // The loop range is set by the original. Let's call original and override.
    }

    // Find next speed in the L ladder
    NSArray *ladder = SpliceKit_getLLadder();
    float nextRate;
    if (currentRate < 0.0) {
        // Playing in reverse → jump to first L speed
        nextRate = [ladder.firstObject floatValue];
    } else {
        nextRate = SpliceKit_nextLadderUp(ladder, currentRate);
    }

    if (fabsf(nextRate - (float)currentRate) > 0.01f) {
        SEL pwrSel = NSSelectorFromString(@"_playWithRate:");
        if ([self respondsToSelector:pwrSel])
            ((void (*)(id, SEL, float))objc_msgSend)(self, pwrSel, nextRate);
    }
}

static void SpliceKit_swizzled_rewind(id self, SEL _cmd, id sender) {
    BOOL stopIsDown = SpliceKit_readBoolIvar(self, "_stopPlayingIsDown");

    if ([sender respondsToSelector:@selector(repeatCount)]) {
        NSInteger rc = ((NSInteger (*)(id, SEL))objc_msgSend)(sender, @selector(repeatCount));
        if (stopIsDown) {
            ((void (*)(id, SEL, id))objc_msgSend)(self, @selector(stepBackward:), sender);
            return;
        }
        if (rc > 0) return;
    } else if (stopIsDown) {
        ((void (*)(id, SEL, id))objc_msgSend)(self, @selector(stepBackward:), sender);
        return;
    }

    SEL endStepSel = NSSelectorFromString(@"_endStepPlayback");
    if ([self respondsToSelector:endStepSel])
        ((void (*)(id, SEL))objc_msgSend)(self, endStepSel);

    double currentRate = 0.0;
    SEL playerSel = @selector(player);
    if ([self respondsToSelector:playerSel]) {
        id player = ((id (*)(id, SEL))objc_msgSend)(self, playerSel);
        if (player) {
            SEL rateSel = NSSelectorFromString(@"rate");
            if ([player respondsToSelector:rateSel])
                currentRate = ((double (*)(id, SEL))objc_msgSend)(player, rateSel);
        }
    }

    NSArray *ladder = SpliceKit_getJLadder();
    float nextRate;
    if (currentRate > 0.0) {
        // Playing forward → jump to first J speed (negative)
        nextRate = -[ladder.firstObject floatValue];
    } else {
        // Already in reverse → go deeper
        nextRate = SpliceKit_nextLadderDown(ladder, currentRate);
    }

    if (fabsf(nextRate - (float)currentRate) > 0.01f) {
        SEL pwrSel = NSSelectorFromString(@"_playWithRate:");
        if ([self respondsToSelector:pwrSel])
            ((void (*)(id, SEL, float))objc_msgSend)(self, pwrSel, nextRate);
    }
}

void SpliceKit_installPlaybackSpeedSwizzle(void) {
    Class cls = objc_getClass("FFPlayerModule");
    if (!cls) {
        SpliceKit_log(@"[Speed] FFPlayerModule not found — swizzle skipped");
        return;
    }

    Method ffMethod = class_getInstanceMethod(cls, @selector(fastForward:));
    if (ffMethod) {
        sOrigFastForward = method_setImplementation(ffMethod, (IMP)SpliceKit_swizzled_fastForward);
        SpliceKit_log(@"[Speed] Swizzled fastForward: on FFPlayerModule");
    }

    Method rwMethod = class_getInstanceMethod(cls, @selector(rewind:));
    if (rwMethod) {
        sOrigRewind = method_setImplementation(rwMethod, (IMP)SpliceKit_swizzled_rewind);
        SpliceKit_log(@"[Speed] Swizzled rewind: on FFPlayerModule");
    }
}

#pragma mark - Range Selection & Batch Export

// Helper: build a CMTime from seconds using the sequence timescale
static SpliceKit_CMTime SpliceKit_buildCMTime(double seconds, id timeline) {
    int32_t timescale = 24000; // default
    SEL seqSel = @selector(sequence);
    if ([timeline respondsToSelector:seqSel]) {
        id sequence = ((id (*)(id, SEL))objc_msgSend)(timeline, seqSel);
        if (sequence) {
            SEL fdSel = NSSelectorFromString(@"frameDuration");
            if ([sequence respondsToSelector:fdSel]) {
                SpliceKit_CMTime fd = ((SpliceKit_CMTime (*)(id, SEL))STRET_MSG)(sequence, fdSel);
                if (fd.timescale > 0) timescale = fd.timescale;
            }
        }
    }
    SpliceKit_CMTime t;
    t.value = (int64_t)(seconds * timescale);
    t.timescale = timescale;
    t.flags = 1; // kCMTimeFlags_Valid
    t.epoch = 0;
    return t;
}

// Helper: simulate a key press in FCP (posts key down + key up events)
static void SpliceKit_simulateKeyPress(unsigned short keyCode, NSString *chars, NSEventModifierFlags mods) {
    id app = ((id (*)(id, SEL))objc_msgSend)(
        objc_getClass("NSApplication"), @selector(sharedApplication));
    id window = ((id (*)(id, SEL))objc_msgSend)(app, @selector(mainWindow));
    NSInteger winNum = window ? [(NSWindow *)window windowNumber] : 0;

    NSEvent *keyDown = [NSEvent keyEventWithType:NSEventTypeKeyDown
                                        location:NSZeroPoint
                                   modifierFlags:mods
                                       timestamp:[[NSProcessInfo processInfo] systemUptime]
                                    windowNumber:winNum
                                         context:nil
                                      characters:chars
                     charactersIgnoringModifiers:chars
                                       isARepeat:NO
                                         keyCode:keyCode];
    [app sendEvent:keyDown];

    NSEvent *keyUp = [NSEvent keyEventWithType:NSEventTypeKeyUp
                                      location:NSZeroPoint
                                 modifierFlags:mods
                                     timestamp:[[NSProcessInfo processInfo] systemUptime]
                                  windowNumber:winNum
                                       context:nil
                                    characters:chars
                   charactersIgnoringModifiers:chars
                                     isARepeat:NO
                                       keyCode:keyCode];
    [app sendEvent:keyUp];
}

// Helper: seek playhead and mark in/out via direct responder chain (no key simulation)
static BOOL SpliceKit_seekAndMark(id timeline, SpliceKit_CMTime time, NSString *actionSelector) {
    // Seek playhead
    SEL setSel = @selector(setPlayheadTime:);
    if (![timeline respondsToSelector:setSel]) return NO;
    ((void (*)(id, SEL, SpliceKit_CMTime))objc_msgSend)(timeline, setSel, time);

    // Let FCP update playhead position
    [[NSRunLoop currentRunLoop] runUntilDate:[NSDate dateWithTimeIntervalSinceNow:0.05]];

    // Send action via responder chain (works for setRangeStart:, setRangeEnd:, clearRange:, etc.)
    id app = ((id (*)(id, SEL))objc_msgSend)(
        objc_getClass("NSApplication"), @selector(sharedApplication));
    SEL actionSel = NSSelectorFromString(actionSelector);
    BOOL sent = ((BOOL (*)(id, SEL, SEL, id, id))objc_msgSend)(
        app, @selector(sendAction:to:from:), actionSel, nil, nil);

    [[NSRunLoop currentRunLoop] runUntilDate:[NSDate dateWithTimeIntervalSinceNow:0.05]];
    return sent;
}

// Batch add markers at specific times using direct ObjC calls (no playhead movement needed)
static NSDictionary *SpliceKit_handleBatchAddMarkers(NSDictionary *params) {
    NSArray *markers = params[@"markers"];
    if (!markers || ![markers isKindOfClass:[NSArray class]] || markers.count == 0) {
        return @{@"error": @"markers array required (each: {time, name, kind})"};
    }

    __block NSDictionary *result = nil;
    SpliceKit_executeOnMainThread(^{
        @try {
            id timeline = SpliceKit_getActiveTimelineModule();
            if (!timeline) { result = @{@"error": @"No active timeline module"}; return; }

            id sequence = ((id (*)(id, SEL))objc_msgSend)(timeline, @selector(sequence));
            if (!sequence) { result = @{@"error": @"No sequence in timeline"}; return; }

            // Get frame duration for marker length
            SpliceKit_CMTime frameDur = {100, 2400, 1, 0}; // default 24fps
            SEL fdSel = NSSelectorFromString(@"frameDuration");
            if ([sequence respondsToSelector:fdSel]) {
                SpliceKit_CMTime fd = ((SpliceKit_CMTime (*)(id, SEL))STRET_MSG)(sequence, fdSel);
                if (fd.timescale > 0) frameDur = fd;
            }

            // Build a list of clips with their timeline start/end times so we can
            // target the correct clip for each marker (not just the longest one).
            // Spine items are sequential, so we compute positions by summing durations.
            id primaryObj = [sequence respondsToSelector:@selector(primaryObject)]
                ? ((id (*)(id, SEL))objc_msgSend)(sequence, @selector(primaryObject)) : nil;
            if (!primaryObj) { result = @{@"error": @"Cannot access primary storyline"}; return; }

            id containedItems = ((id (*)(id, SEL))objc_msgSend)(primaryObj, @selector(containedItems));
            NSMutableArray *clipInfos = [NSMutableArray array];

            // Detect timeline start offset (e.g. 01:00:00:00 = 3600s) using the first clip's
            // effective range. Input times are relative to content (0 = first frame), so we
            // add this offset when creating CMTimes for marker placement.
            double timelineStartOffset = 0;
            SEL erSel = NSSelectorFromString(@"effectiveRangeOfObject:");
            BOOL canGetRange = [primaryObj respondsToSelector:erSel];

            if ([containedItems isKindOfClass:[NSArray class]]) {
                double cumulativeStart = 0;
                BOOL firstClip = YES;
                for (id item in (NSArray *)containedItems) {
                    if (![item respondsToSelector:@selector(duration)]) continue;
                    SpliceKit_CMTime d = ((SpliceKit_CMTime (*)(id, SEL))STRET_MSG)(item, @selector(duration));
                    double dur = (d.timescale > 0) ? (double)d.value / d.timescale : 0;

                    // Get start offset from first clip's absolute position
                    if (firstClip && canGetRange) {
                        firstClip = NO;
                        @try {
                            SpliceKit_CMTimeRange range = ((SpliceKit_CMTimeRange (*)(id, SEL, id))STRET_MSG)(
                                primaryObj, erSel, item);
                            double absStart = (range.start.timescale > 0) ? (double)range.start.value / range.start.timescale : 0;
                            timelineStartOffset = absStart; // e.g. 3600.0 for 01:00:00:00
                        } @catch (NSException *e) {}
                    }

                    [clipInfos addObject:@{@"clip": item, @"start": @(cumulativeStart), @"end": @(cumulativeStart + dur)}];
                    cumulativeStart += dur;
                }
            }
            if (clipInfos.count == 0) { result = @{@"error": @"No clips found in timeline"}; return; }

            SEL addSel = NSSelectorFromString(@"actionAddMarkerToAnchoredObject:isToDo:isChapter:withRange:error:");
            if (![sequence respondsToSelector:addSel]) {
                result = @{@"error": @"Sequence does not support actionAddMarkerToAnchoredObject:"};
                return;
            }

            // For renaming markers after creation
            SEL renameSel = NSSelectorFromString(@"actionChangeMarkerDisplayName:marker:error:");
            BOOL canRename = [timeline respondsToSelector:renameSel];

            typedef BOOL (*AddMarkerFn)(id, SEL, id, BOOL, BOOL, SpliceKit_CMTimeRange, NSError **);
            AddMarkerFn addMarker = (AddMarkerFn)objc_msgSend;

            int32_t ts = frameDur.timescale > 0 ? frameDur.timescale : 600;
            NSUInteger applied = 0;
            NSMutableArray *results = [NSMutableArray array];

            for (NSDictionary *m in markers) {
                double t = [m[@"time"] doubleValue];
                NSString *name = m[@"name"];
                NSString *kind = m[@"kind"] ?: @"standard";
                BOOL isToDo = [kind isEqualToString:@"todo"];
                BOOL isChapter = [kind isEqualToString:@"chapter"];

                // Find the clip that contains this time
                id targetClip = nil;
                for (NSDictionary *ci in clipInfos) {
                    double cStart = [ci[@"start"] doubleValue];
                    double cEnd = [ci[@"end"] doubleValue];
                    if (t >= cStart - 0.01 && t < cEnd + 0.01) {
                        targetClip = ci[@"clip"];
                        break;
                    }
                }
                // Fallback: use the last clip if marker time is past all clips
                if (!targetClip) targetClip = [clipInfos lastObject][@"clip"];

                // Add timeline start offset so relative times map to absolute FCP positions
                double absoluteTime = t + timelineStartOffset;
                SpliceKit_CMTime markerTime = {(int64_t)round(absoluteTime * ts), ts, 1, 0};
                SpliceKit_CMTimeRange range = {markerTime, frameDur};
                NSError *err = nil;
                BOOL ok = addMarker(sequence, addSel, targetClip, isToDo, isChapter, range, &err);
                if (ok) {
                    applied++;

                    // Rename the marker if a name was provided
                    if (name.length > 0 && canRename) {
                        // Find the marker we just added on this clip by looking for a marker
                        // at the exact time we placed it
                        SEL markersSel = NSSelectorFromString(@"markersInTimeRange:");
                        if ([sequence respondsToSelector:markersSel]) {
                            SpliceKit_CMTime searchEnd = markerTime;
                            searchEnd.value += frameDur.value;
                            SpliceKit_CMTimeRange searchRange = {markerTime, frameDur};
                            id foundMarkers = ((id (*)(id, SEL, SpliceKit_CMTimeRange))objc_msgSend)(
                                sequence, markersSel, searchRange);
                            if ([foundMarkers respondsToSelector:@selector(lastObject)]) {
                                id marker = ((id (*)(id, SEL))objc_msgSend)(foundMarkers, @selector(lastObject));
                                if (marker) {
                                    NSError *renameErr = nil;
                                    ((void (*)(id, SEL, id, id, NSError **))objc_msgSend)(
                                        timeline, renameSel, name, marker, &renameErr);
                                }
                            }
                        }
                    }

                    [results addObject:@{@"time": @(t), @"success": @YES}];
                } else {
                    [results addObject:@{@"time": @(t), @"success": @NO,
                        @"error": err ? [err localizedDescription] : @"unknown"}];
                }
            }

            result = @{
                @"status": @"ok",
                @"count": @(markers.count),
                @"applied": @(applied),
                @"markers": results,
            };
        } @catch (NSException *e) {
            result = @{@"error": [NSString stringWithFormat:@"Exception: %@", e.reason]};
        }
    });
    return result ?: @{@"error": @"Failed to add markers"};
}

// Batch blade at specific times using seek + blade (no manual playhead stepping needed)
static NSDictionary *SpliceKit_handleBladeAtTimes(NSDictionary *params) {
    NSArray *times = params[@"times"];
    if (!times || ![times isKindOfClass:[NSArray class]] || times.count == 0) {
        return @{@"error": @"times array required (list of seconds, e.g. [3.0, 6.0, 9.0])"};
    }

    // Sort times ascending so we blade left-to-right (avoids offset issues)
    NSArray *sortedTimes = [times sortedArrayUsingSelector:@selector(compare:)];

    __block NSDictionary *result = nil;
    SpliceKit_executeOnMainThread(^{
        @try {
            id timeline = SpliceKit_getActiveTimelineModule();
            if (!timeline) { result = @{@"error": @"No active timeline module"}; return; }

            NSUInteger applied = 0;
            NSMutableArray *results = [NSMutableArray array];

            for (NSNumber *timeNum in sortedTimes) {
                double t = [timeNum doubleValue];
                SpliceKit_handlePlaybackSeek(@{@"seconds": @(t)});
                [NSThread sleepForTimeInterval:0.03];
                NSDictionary *bladeResult = SpliceKit_handleTimelineAction(@{@"action": @"blade"});

                BOOL ok = bladeResult && !bladeResult[@"error"];
                if (ok) {
                    applied++;
                    [results addObject:@{@"time": @(t), @"success": @YES}];
                } else {
                    [results addObject:@{@"time": @(t), @"success": @NO,
                        @"error": bladeResult[@"error"] ?: @"blade failed"}];
                }
            }

            result = @{
                @"status": @"ok",
                @"count": @(sortedTimes.count),
                @"applied": @(applied),
                @"cuts": results,
            };
        } @catch (NSException *e) {
            result = @{@"error": [NSString stringWithFormat:@"Exception: %@", e.reason]};
        }
    });
    return result ?: @{@"error": @"Failed to blade at times"};
}

static double SpliceKit_secondsFromTime(SpliceKit_CMTime t) {
    if (t.timescale <= 0) return 0.0;
    return (double)t.value / (double)t.timescale;
}

static BOOL SpliceKit_tryReadTimelineRange(id primaryObj, id item, SpliceKit_CMTimeRange *outRange) {
    if (!primaryObj || !item || !outRange) return NO;
    SEL erSel = NSSelectorFromString(@"effectiveRangeOfObject:");
    if (![primaryObj respondsToSelector:erSel]) return NO;
    @try {
        *outRange = ((SpliceKit_CMTimeRange (*)(id, SEL, id))STRET_MSG)(primaryObj, erSel, item);
        return outRange->start.timescale > 0 && outRange->duration.timescale > 0;
    } @catch (NSException *e) {}
    return NO;
}

static BOOL SpliceKit_tryReadLocalAudioRange(id item, SpliceKit_CMTimeRange *outRange) {
    if (!item || !outRange) return NO;

    SEL audioSel = NSSelectorFromString(@"audioClippedRange");
    if ([item respondsToSelector:audioSel]) {
        @try {
            SpliceKit_CMTimeRange range = ((SpliceKit_CMTimeRange (*)(id, SEL))STRET_MSG)(item, audioSel);
            if (range.start.timescale > 0 && range.duration.timescale > 0) {
                *outRange = range;
                return YES;
            }
        } @catch (NSException *e) {}
    }

    SEL clipSel = NSSelectorFromString(@"clippedRange");
    if ([item respondsToSelector:clipSel]) {
        @try {
            SpliceKit_CMTimeRange range = ((SpliceKit_CMTimeRange (*)(id, SEL))STRET_MSG)(item, clipSel);
            if (range.start.timescale > 0 && range.duration.timescale > 0) {
                *outRange = range;
                return YES;
            }
        } @catch (NSException *e) {}
    }

    return NO;
}

static NSArray<NSNumber *> *SpliceKit_sortedUniqueSeconds(NSArray<NSNumber *> *values, double epsilon) {
    if (!values || values.count == 0) return @[];

    NSArray<NSNumber *> *sorted = [values sortedArrayUsingSelector:@selector(compare:)];
    NSMutableArray<NSNumber *> *unique = [NSMutableArray arrayWithCapacity:sorted.count];
    double last = 0.0;
    BOOL hasLast = NO;
    for (NSNumber *num in sorted) {
        double value = [num doubleValue];
        if (!isfinite(value)) continue;
        if (!hasLast || fabs(value - last) > epsilon) {
            [unique addObject:@(value)];
            last = value;
            hasLast = YES;
        }
    }
    return unique;
}

static NSArray<NSNumber *> *SpliceKit_copyTimingMetadataSecondsForType(id clip, NSInteger type) {
    if (!clip || ![clip respondsToSelector:@selector(newTimingMetadata)]) return @[];

    id timing = ((id (*)(id, SEL))objc_msgSend)(clip, @selector(newTimingMetadata));
    if (!timing) return @[];

    SEL typeSel = NSSelectorFromString(@"newTimingMetadataForType:");
    if (![timing respondsToSelector:typeSel]) return @[];

    id entriesValue = ((id (*)(id, SEL, NSInteger))objc_msgSend)(timing, typeSel, type);
    NSArray *entries = SpliceKit_mixerArrayFromContainer(entriesValue);
    if (!entries || entries.count == 0) return @[];

    SEL timeSel = NSSelectorFromString(@"time");
    NSMutableArray<NSNumber *> *times = [NSMutableArray arrayWithCapacity:entries.count];
    for (id entry in entries) {
        if (![entry respondsToSelector:timeSel]) continue;
        @try {
            SpliceKit_CMTime time = ((SpliceKit_CMTime (*)(id, SEL))STRET_MSG)(entry, timeSel);
            double seconds = SpliceKit_secondsFromTime(time);
            if (isfinite(seconds)) [times addObject:@(seconds)];
        } @catch (NSException *e) {}
    }

    return SpliceKit_sortedUniqueSeconds(times, 0.0001);
}

static double SpliceKit_copyTimingMetadataTempo(id clip) {
    if (!clip || ![clip respondsToSelector:@selector(newTimingMetadata)]) return 0.0;

    id timing = ((id (*)(id, SEL))objc_msgSend)(clip, @selector(newTimingMetadata));
    if (!timing) return 0.0;

    SEL typeSel = NSSelectorFromString(@"newTimingMetadataForType:");
    if (![timing respondsToSelector:typeSel]) return 0.0;

    id entriesValue = ((id (*)(id, SEL, NSInteger))objc_msgSend)(timing, typeSel, 8);
    NSArray *entries = SpliceKit_mixerArrayFromContainer(entriesValue);
    if (!entries || entries.count == 0) return 0.0;

    id first = entries.firstObject;
    if (!first) return 0.0;

    SEL dataSel = NSSelectorFromString(@"data");
    if (![first respondsToSelector:dataSel]) return 0.0;

    id data = ((id (*)(id, SEL))objc_msgSend)(first, dataSel);
    SEL valueSel = NSSelectorFromString(@"value");
    if (!data || ![data respondsToSelector:valueSel]) return 0.0;

    @try {
        return ((float (*)(id, SEL))objc_msgSend)(data, valueSel);
    } @catch (NSException *e) {}
    return 0.0;
}

static NSArray<NSNumber *> *SpliceKit_translateTimingMetadataToTimeline(id clip,
                                                                        id primaryObj,
                                                                        NSString *gridMode,
                                                                        double *outStartSec,
                                                                        double *outEndSec,
                                                                        double *outTempo) {
    if (!clip || !primaryObj) return @[];

    SpliceKit_CMTimeRange timelineRange;
    if (!SpliceKit_tryReadTimelineRange(primaryObj, clip, &timelineRange)) return @[];

    SpliceKit_CMTimeRange localRange;
    if (!SpliceKit_tryReadLocalAudioRange(clip, &localRange)) return @[];

    double timelineStartSec = SpliceKit_secondsFromTime(timelineRange.start);
    double timelineDurationSec = SpliceKit_secondsFromTime(timelineRange.duration);
    double timelineEndSec = timelineStartSec + timelineDurationSec;
    double localStartSec = SpliceKit_secondsFromTime(localRange.start);
    double localDurationSec = SpliceKit_secondsFromTime(localRange.duration);
    double localEndSec = localStartSec + localDurationSec;

    if (outStartSec) *outStartSec = timelineStartSec;
    if (outEndSec) *outEndSec = timelineEndSec;
    if (outTempo) *outTempo = SpliceKit_copyTimingMetadataTempo(clip);

    NSArray<NSNumber *> *beats = SpliceKit_copyTimingMetadataSecondsForType(clip, 1);
    NSArray<NSNumber *> *bars = SpliceKit_copyTimingMetadataSecondsForType(clip, 2);
    NSArray<NSNumber *> *sections = SpliceKit_copyTimingMetadataSecondsForType(clip, 4);

    NSMutableArray<NSNumber *> *timelinePoints = [NSMutableArray array];
    NSString *mode = (gridMode ?: @"beat").lowercaseString;
    BOOL useBars = [mode isEqualToString:@"bar"];
    BOOL useSections = [mode isEqualToString:@"section"];
    BOOL useHalfBeats = [mode isEqualToString:@"half"] || [mode isEqualToString:@"half_beat"];
    BOOL useQuarterBeats = [mode isEqualToString:@"quarter"] || [mode isEqualToString:@"quarter_beat"];

    NSArray<NSNumber *> *base = beats;
    if (useBars) base = bars;
    if (useSections) base = sections;

    for (NSNumber *num in base) {
        double localSec = [num doubleValue];
        if (localSec + 0.0001 < localStartSec || localSec - 0.0001 > localEndSec) continue;
        double timelineSec = timelineStartSec + (localSec - localStartSec);
        if (timelineSec + 0.0001 < timelineStartSec || timelineSec - 0.0001 > timelineEndSec) continue;
        [timelinePoints addObject:@(timelineSec)];
    }

    if (useQuarterBeats && beats.count > 1) {
        for (NSUInteger i = 0; i + 1 < beats.count; i++) {
            double left = [beats[i] doubleValue];
            double right = [beats[i + 1] doubleValue];
            if (right <= left) continue;
            double delta = right - left;
            double quarter = left + (delta * 0.25);
            double midpoint = left + (delta * 0.5);
            double threeQuarter = left + (delta * 0.75);
            for (NSNumber *subdivision in @[@(quarter), @(midpoint), @(threeQuarter)]) {
                double localSec = [subdivision doubleValue];
                if (localSec + 0.0001 < localStartSec || localSec - 0.0001 > localEndSec) continue;
                double timelineSec = timelineStartSec + (localSec - localStartSec);
                if (timelineSec + 0.0001 < timelineStartSec || timelineSec - 0.0001 > timelineEndSec) continue;
                [timelinePoints addObject:@(timelineSec)];
            }
        }
    } else if (useHalfBeats && beats.count > 1) {
        for (NSUInteger i = 0; i + 1 < beats.count; i++) {
            double left = [beats[i] doubleValue];
            double right = [beats[i + 1] doubleValue];
            if (right <= left) continue;
            double midpoint = left + ((right - left) * 0.5);
            if (midpoint + 0.0001 < localStartSec || midpoint - 0.0001 > localEndSec) continue;
            double timelineSec = timelineStartSec + (midpoint - localStartSec);
            if (timelineSec + 0.0001 < timelineStartSec || timelineSec - 0.0001 > timelineEndSec) continue;
            [timelinePoints addObject:@(timelineSec)];
        }
    }

    return SpliceKit_sortedUniqueSeconds(timelinePoints, 0.0001);
}

static BOOL SpliceKit_boolForSelector(id item, NSString *selectorName) {
    if (!item || selectorName.length == 0) return NO;
    SEL sel = NSSelectorFromString(selectorName);
    if (![item respondsToSelector:sel]) return NO;
    @try {
        return ((BOOL (*)(id, SEL))objc_msgSend)(item, sel);
    } @catch (NSException *e) {}
    return NO;
}

static NSInteger SpliceKit_laneForItem(id item) {
    if (!item) return 0;
    SEL laneSel = NSSelectorFromString(@"anchoredLane");
    if (![item respondsToSelector:laneSel]) return 0;
    @try {
        return (NSInteger)((long long (*)(id, SEL))objc_msgSend)(item, laneSel);
    } @catch (NSException *e) {}
    return 0;
}

static NSString *SpliceKit_displayNameForItem(id item) {
    if (!item || ![item respondsToSelector:@selector(displayName)]) return @"";
    @try {
        id name = ((id (*)(id, SEL))objc_msgSend)(item, @selector(displayName));
        return name ?: @"";
    } @catch (NSException *e) {}
    return @"";
}

static void SpliceKit_collectVisibleTimelineEntries(id item,
                                                    id primaryObj,
                                                    NSMutableArray<NSDictionary *> *out,
                                                    NSMutableSet<NSString *> *visited) {
    if (!item || !out || !visited) return;

    NSString *pointerKey = SpliceKit_handlePointerKey(item);
    if (pointerKey.length == 0 || [visited containsObject:pointerKey]) return;
    [visited addObject:pointerKey];
    BOOL skipSelf = SpliceKit_mixerIsSkippableItem(item);
    BOOL hasVideo = NO;
    BOOL isConnectedStoryline = NO;

    if (!skipSelf) {
        SpliceKit_CMTimeRange range;
        if (SpliceKit_tryReadTimelineRange(primaryObj, item, &range)) {
            double startSec = SpliceKit_secondsFromTime(range.start);
            double durationSec = SpliceKit_secondsFromTime(range.duration);
            double endSec = startSec + durationSec;
            if (isfinite(startSec) && isfinite(endSec) && endSec > startSec + 0.0001) {
                hasVideo = SpliceKit_boolForSelector(item, @"hasVideo");
                BOOL hasAudio = SpliceKit_boolForSelector(item, @"hasAudio");
                BOOL isAudioOnly = SpliceKit_boolForSelector(item, @"isAudioOnly");
                isConnectedStoryline = SpliceKit_boolForSelector(item, @"isConnectedStoryline");
                BOOL hasTimingMetadata = SpliceKit_boolForSelector(item, @"hasTimingMetadata");
                BOOL beatGridEnabled = SpliceKit_boolForSelector(item, @"beatGridEnabled");

                [out addObject:@{
                    @"item": item,
                    @"pointerKey": pointerKey,
                    @"name": SpliceKit_displayNameForItem(item),
                    @"start": @(startSec),
                    @"end": @(endSec),
                    @"lane": @(SpliceKit_laneForItem(item)),
                    @"hasVideo": @(hasVideo),
                    @"hasAudio": @(hasAudio),
                    @"isAudioOnly": @(isAudioOnly),
                    @"isConnectedStoryline": @(isConnectedStoryline),
                    @"hasTimingMetadata": @(hasTimingMetadata),
                    @"beatGridEnabled": @(beatGridEnabled),
                }];
            }
        }
    }

    SEL anchoredSel = NSSelectorFromString(@"anchoredItems");
    NSArray *anchored = [item respondsToSelector:anchoredSel]
        ? SpliceKit_mixerArrayFromContainer(((id (*)(id, SEL))objc_msgSend)(item, anchoredSel))
        : nil;

    SEL containedSel = NSSelectorFromString(@"containedItems");
    NSArray *contained = [item respondsToSelector:containedSel]
        ? SpliceKit_mixerArrayFromContainer(((id (*)(id, SEL))objc_msgSend)(item, containedSel))
        : nil;

    BOOL recurseContained = isConnectedStoryline || (!hasVideo && SpliceKit_mixerIsCollectionLike(item));
    if (recurseContained) {
        for (id child in contained) {
            SpliceKit_collectVisibleTimelineEntries(child, primaryObj, out, visited);
        }
    }
    for (id child in anchored) {
        SpliceKit_collectVisibleTimelineEntries(child, primaryObj, out, visited);
    }
}

static uint64_t SpliceKit_nextRandom(uint64_t *state) {
    *state = (*state * 6364136223846793005ULL) + 1442695040888963407ULL;
    return *state;
}

static NSInteger SpliceKit_chooseRandomAssemblyStep(NSInteger segmentMinStep,
                                                    NSInteger segmentMaxStep,
                                                    NSDictionary<NSNumber *, NSNumber *> *stepWeights,
                                                    uint64_t *rngState) {
    if (segmentMinStep < 1) segmentMinStep = 1;
    if (segmentMaxStep < segmentMinStep) segmentMaxStep = segmentMinStep;

    NSInteger totalWeight = 0;
    if (stepWeights.count > 0) {
        for (NSInteger step = segmentMinStep; step <= segmentMaxStep; step++) {
            NSInteger weight = [stepWeights[@(step)] integerValue];
            if (weight > 0) totalWeight += weight;
        }
    }

    if (totalWeight > 0) {
        NSInteger pick = (NSInteger)(SpliceKit_nextRandom(rngState) % (uint64_t)totalWeight);
        NSInteger cumulative = 0;
        for (NSInteger step = segmentMinStep; step <= segmentMaxStep; step++) {
            NSInteger weight = [stepWeights[@(step)] integerValue];
            if (weight <= 0) continue;
            cumulative += weight;
            if (pick < cumulative) return step;
        }
    }

    if (segmentMaxStep <= segmentMinStep) return segmentMinStep;
    NSInteger span = segmentMaxStep - segmentMinStep + 1;
    return segmentMinStep + (NSInteger)(SpliceKit_nextRandom(rngState) % (uint64_t)span);
}

static id SpliceKit_findSequenceNamedInActiveLibraries(NSString *projectName);

static NSDictionary *SpliceKit_buildVisibleEntryContextForSequence(id sequence) {
    if (!sequence) {
        return @{@"error": @"Missing sequence"};
    }

    id primaryObj = [sequence respondsToSelector:@selector(primaryObject)]
        ? ((id (*)(id, SEL))objc_msgSend)(sequence, @selector(primaryObject)) : nil;
    if (!primaryObj) {
        return @{@"error": @"Sequence has no primary storyline"};
    }

    NSArray *rootItems = SpliceKit_mixerArrayFromContainer(
        ((id (*)(id, SEL))objc_msgSend)(primaryObj, @selector(containedItems))) ?: @[];
    NSMutableArray<NSDictionary *> *visibleEntries = [NSMutableArray array];
    NSMutableSet<NSString *> *visited = [NSMutableSet set];
    for (id item in rootItems) {
        SpliceKit_collectVisibleTimelineEntries(item, primaryObj, visibleEntries, visited);
    }

    return @{
        @"sequence": sequence,
        @"primaryObject": primaryObj,
        @"visibleEntries": visibleEntries,
        @"sequenceName": SpliceKit_displayNameForItem(sequence) ?: @"",
    };
}

static NSDictionary *SpliceKit_findVisibleEntryContextNamed(NSString *projectName) {
    if (projectName.length == 0) {
        return @{@"error": @"Missing project name"};
    }

    id sequence = SpliceKit_findSequenceNamedInActiveLibraries(projectName);
    if (!sequence) {
        return @{@"error": [NSString stringWithFormat:@"Couldn't find sequence named \"%@\"", projectName]};
    }

    return SpliceKit_buildVisibleEntryContextForSequence(sequence);
}

static double SpliceKit_quantizeSecondsToFrameGrid(double seconds, double frameSeconds);

static NSDictionary *SpliceKit_handleTrimClipsToBeats(NSDictionary *params) {
    NSString *sourceHandle = [params[@"sourceHandle"] isKindOfClass:[NSString class]] ? params[@"sourceHandle"] : nil;
    NSArray *targetHandles = [params[@"targetHandles"] isKindOfClass:[NSArray class]] ? params[@"targetHandles"] : nil;
    NSString *grid = [params[@"grid"] isKindOfClass:[NSString class]] ? [params[@"grid"] lowercaseString] : @"beat";
    NSString *targetMode = [params[@"targetMode"] isKindOfClass:[NSString class]]
        ? [params[@"targetMode"] lowercaseString] : @"auto";
    BOOL randomize = [params[@"randomize"] boolValue];
    BOOL dryRun = [params[@"dryRun"] boolValue];
    NSInteger randomMinStep = params[@"randomMinStep"] ? [params[@"randomMinStep"] integerValue] : 1;
    NSInteger randomMaxStep = params[@"randomMaxStep"] ? [params[@"randomMaxStep"] integerValue] : 4;
    long long randomSeed = params[@"randomSeed"] ? [params[@"randomSeed"] longLongValue] : 1337;
    double minTrimSeconds = params[@"minTrimSeconds"] ? [params[@"minTrimSeconds"] doubleValue] : -1.0;
    double minResultDuration = params[@"minResultDuration"] ? [params[@"minResultDuration"] doubleValue] : -1.0;
    __block double effectiveMinTrimSeconds = minTrimSeconds;
    __block double effectiveMinResultDuration = minResultDuration;

    if ([grid isEqualToString:@"random"]) {
        grid = @"beat";
        randomize = YES;
    } else if ([grid isEqualToString:@"random_half"] || [grid isEqualToString:@"random_half_beat"]) {
        grid = @"half_beat";
        randomize = YES;
    } else if ([grid isEqualToString:@"random_quarter"] || [grid isEqualToString:@"random_quarter_beat"]) {
        grid = @"quarter_beat";
        randomize = YES;
    }

    NSSet *allowed = [NSSet setWithArray:@[@"beat", @"half", @"half_beat", @"quarter", @"quarter_beat", @"bar", @"section"]];
    if (![allowed containsObject:grid]) {
        return @{@"error": @"grid must be one of: beat, half_beat, quarter_beat, bar, section, random, random_half_beat, random_quarter_beat"};
    }
    if (![@[@"auto", @"selected", @"overlay", @"all"] containsObject:targetMode]) {
        return @{@"error": @"targetMode must be one of: auto, selected, overlay, all"};
    }

    if (randomMinStep < 1) randomMinStep = 1;
    if (randomMaxStep < randomMinStep) randomMaxStep = randomMinStep;

    __block NSDictionary *result = nil;
    SpliceKit_executeOnMainThread(^{
        @try {
            id timeline = SpliceKit_getActiveTimelineModule();
            if (!timeline) { result = @{@"error": @"No active timeline module"}; return; }

            id sequence = [timeline respondsToSelector:@selector(sequence)]
                ? ((id (*)(id, SEL))objc_msgSend)(timeline, @selector(sequence)) : nil;
            if (!sequence) { result = @{@"error": @"No sequence in timeline"}; return; }

            id primaryObj = [sequence respondsToSelector:@selector(primaryObject)]
                ? ((id (*)(id, SEL))objc_msgSend)(sequence, @selector(primaryObject)) : nil;
            if (!primaryObj) { result = @{@"error": @"Cannot access primary storyline"}; return; }

            SpliceKit_CMTime frameDuration = {100, 3000, 1, 0};
            SEL fdSel = NSSelectorFromString(@"frameDuration");
            if ([sequence respondsToSelector:fdSel]) {
                SpliceKit_CMTime fd = ((SpliceKit_CMTime (*)(id, SEL))STRET_MSG)(sequence, fdSel);
                if (fd.timescale > 0 && fd.value > 0) frameDuration = fd;
            }
            double frameSeconds = MAX(0.001, SpliceKit_secondsFromTime(frameDuration));
            if (effectiveMinTrimSeconds < 0.0) effectiveMinTrimSeconds = frameSeconds;
            if (effectiveMinResultDuration < 0.0) effectiveMinResultDuration = frameSeconds * 2.0;

            NSArray *rootItems = SpliceKit_mixerArrayFromContainer(((id (*)(id, SEL))objc_msgSend)(primaryObj, @selector(containedItems)));
            if (!rootItems || rootItems.count == 0) {
                result = @{@"error": @"No clips found in timeline"};
                return;
            }

            NSMutableArray<NSDictionary *> *visibleEntries = [NSMutableArray array];
            NSMutableSet<NSString *> *visited = [NSMutableSet set];
            for (id item in rootItems) {
                SpliceKit_collectVisibleTimelineEntries(item, primaryObj, visibleEntries, visited);
            }
            if (visibleEntries.count == 0) {
                result = @{@"error": @"No visible timeline items found"};
                return;
            }

            NSArray *selectedItems = nil;
            NSMutableSet<NSString *> *selectedKeys = [NSMutableSet set];
            SEL selectedSel = NSSelectorFromString(@"selectedItems:includeItemBeforePlayheadIfLast:");
            if ([timeline respondsToSelector:selectedSel]) {
                id selItems = ((id (*)(id, SEL, BOOL, BOOL))objc_msgSend)(timeline, selectedSel, NO, NO);
                selectedItems = SpliceKit_mixerArrayFromContainer(selItems);
            } else if ([timeline respondsToSelector:@selector(selectedItems)]) {
                selectedItems = SpliceKit_mixerArrayFromContainer(((id (*)(id, SEL))objc_msgSend)(timeline, @selector(selectedItems)));
            }
            for (id selectedItem in selectedItems) {
                NSString *pointerKey = SpliceKit_handlePointerKey(selectedItem);
                if (pointerKey.length > 0) [selectedKeys addObject:pointerKey];
            }

            NSDictionary *sourceEntry = nil;
            NSString *sourceKey = nil;
            if (sourceHandle.length > 0) {
                id sourceObj = SpliceKit_resolveHandle(sourceHandle);
                if (!sourceObj) {
                    result = @{@"error": [NSString stringWithFormat:@"Source handle not found: %@", sourceHandle]};
                    return;
                }
                sourceKey = SpliceKit_handlePointerKey(sourceObj);
                for (NSDictionary *entry in visibleEntries) {
                    if ([entry[@"pointerKey"] isEqualToString:sourceKey]) {
                        sourceEntry = entry;
                        break;
                    }
                }
                if (!sourceEntry) {
                    result = @{@"error": @"Source clip is not visible in the active timeline"};
                    return;
                }
            } else {
                NSArray *orderedEntries = [visibleEntries sortedArrayUsingComparator:^NSComparisonResult(NSDictionary *lhs, NSDictionary *rhs) {
                    return [lhs[@"start"] compare:rhs[@"start"]];
                }];
                for (NSDictionary *entry in orderedEntries) {
                    if (![selectedKeys containsObject:entry[@"pointerKey"]]) continue;
                    if (![entry[@"hasTimingMetadata"] boolValue] || ![entry[@"hasAudio"] boolValue]) continue;
                    sourceEntry = entry;
                    break;
                }
                if (!sourceEntry) {
                    for (NSDictionary *entry in orderedEntries) {
                        if (![entry[@"hasTimingMetadata"] boolValue] || ![entry[@"hasAudio"] boolValue]) continue;
                        if (![entry[@"beatGridEnabled"] boolValue]) continue;
                        sourceEntry = entry;
                        break;
                    }
                }
                if (!sourceEntry) {
                    for (NSDictionary *entry in orderedEntries) {
                        if ([entry[@"hasTimingMetadata"] boolValue] && [entry[@"hasAudio"] boolValue]) {
                            sourceEntry = entry;
                            break;
                        }
                    }
                }
                if (!sourceEntry) {
                    result = @{@"error": @"No beat-detected audio clip found in the active timeline. Select one or pass sourceHandle."};
                    return;
                }
                sourceKey = sourceEntry[@"pointerKey"];
            }

            id sourceItem = sourceEntry[@"item"];
            if (!SpliceKit_boolForSelector(sourceItem, @"hasTimingMetadata")) {
                result = @{@"error": @"Source clip does not have Apple timing metadata. Run beat detection on it first."};
                return;
            }
            SpliceKit_CMTimeRange sourceClipRange = SpliceKit_clipRangeForItem(sourceItem);

            double sourceStartSec = 0.0;
            double sourceEndSec = 0.0;
            double tempo = 0.0;
            NSArray<NSNumber *> *rawTimelineGrid = SpliceKit_translateTimingMetadataToTimeline(
                sourceItem, primaryObj, grid, &sourceStartSec, &sourceEndSec, &tempo);
            if (rawTimelineGrid.count == 0) {
                result = @{@"error": @"Source clip has no usable timing metadata for the requested grid"};
                return;
            }

            NSMutableArray<NSNumber *> *quantizedTimelineGrid = [NSMutableArray arrayWithCapacity:rawTimelineGrid.count];
            for (NSNumber *markerNum in rawTimelineGrid) {
                double markerSec = SpliceKit_quantizeSecondsToFrameGrid([markerNum doubleValue], frameSeconds);
                if (markerSec > 0.0) [quantizedTimelineGrid addObject:@(markerSec)];
            }
            NSArray<NSNumber *> *timelineGrid = SpliceKit_sortedUniqueSeconds(
                quantizedTimelineGrid, frameSeconds * 0.25);
            if (timelineGrid.count == 0) {
                result = @{@"error": @"Source clip has no frame-quantized timing metadata for the requested grid"};
                return;
            }

            NSMutableSet<NSString *> *requestedTargetKeys = [NSMutableSet set];
            for (id handleValue in targetHandles) {
                if (![handleValue isKindOfClass:[NSString class]]) continue;
                id targetObj = SpliceKit_resolveHandle(handleValue);
                NSString *pointerKey = SpliceKit_handlePointerKey(targetObj);
                if (pointerKey.length > 0) [requestedTargetKeys addObject:pointerKey];
            }

            BOOL haveSelectedVideoTargets = NO;
            BOOL haveOverlayTargets = NO;
            NSInteger sourceLane = [sourceEntry[@"lane"] integerValue];
            BOOL sourceIsAudioOnly = [sourceEntry[@"hasAudio"] boolValue] && ![sourceEntry[@"hasVideo"] boolValue];
            for (NSDictionary *entry in visibleEntries) {
                if ([entry[@"pointerKey"] isEqualToString:sourceKey]) continue;
                if (![entry[@"hasVideo"] boolValue]) continue;
                if ([entry[@"isConnectedStoryline"] boolValue]) continue;
                if ([selectedKeys containsObject:entry[@"pointerKey"]]) haveSelectedVideoTargets = YES;
                if ([entry[@"lane"] integerValue] != sourceLane) haveOverlayTargets = YES;
            }

            NSMutableArray<NSDictionary *> *targetEntries = [NSMutableArray array];
            for (NSDictionary *entry in visibleEntries) {
                NSString *pointerKey = entry[@"pointerKey"];
                if ([pointerKey isEqualToString:sourceKey]) continue;
                if (![entry[@"hasVideo"] boolValue]) continue;
                if ([entry[@"isConnectedStoryline"] boolValue]) continue;

                if (requestedTargetKeys.count > 0) {
                    if (![requestedTargetKeys containsObject:pointerKey]) continue;
                } else if ([targetMode isEqualToString:@"selected"]) {
                    if (![selectedKeys containsObject:pointerKey]) continue;
                } else if ([targetMode isEqualToString:@"overlay"]) {
                    if ([entry[@"lane"] integerValue] == sourceLane) continue;
                } else if ([targetMode isEqualToString:@"auto"]) {
                    if (haveSelectedVideoTargets) {
                        if (![selectedKeys containsObject:pointerKey]) continue;
                    } else if (sourceIsAudioOnly && haveOverlayTargets) {
                        if ([entry[@"lane"] integerValue] == sourceLane) continue;
                    }
                }

                [targetEntries addObject:entry];
            }

            if (targetEntries.count == 0) {
                result = @{@"error": @"No target video clips found to trim"};
                return;
            }

            [targetEntries sortUsingComparator:^NSComparisonResult(NSDictionary *lhs, NSDictionary *rhs) {
                NSComparisonResult startCmp = [lhs[@"start"] compare:rhs[@"start"]];
                if (startCmp != NSOrderedSame) return startCmp;
                return [lhs[@"lane"] compare:rhs[@"lane"]];
            }];

            NSMutableArray<NSDictionary *> *plan = [NSMutableArray array];
            uint64_t rngState = (uint64_t)randomSeed;
            NSUInteger planned = 0;

            for (NSDictionary *entry in targetEntries) {
                double clipStart = [entry[@"start"] doubleValue];
                double clipEnd = [entry[@"end"] doubleValue];
                double currentDuration = clipEnd - clipStart;
                NSString *name = entry[@"name"] ?: @"";
                NSString *handle = SpliceKit_storeHandle(entry[@"item"]);

                BOOL alreadyAligned = NO;
                for (NSNumber *markerNum in timelineGrid) {
                    double markerSec = [markerNum doubleValue];
                    if (fabs(markerSec - clipEnd) <= (frameSeconds * 0.25)) {
                        alreadyAligned = YES;
                        break;
                    }
                }
                if (alreadyAligned) {
                    [plan addObject:[NSMutableDictionary dictionaryWithDictionary:@{
                        @"handle": handle,
                        @"name": name,
                        @"start": @(clipStart),
                        @"end": @(clipEnd),
                        @"status": @"skipped",
                        @"reason": @"Clip already ends on a beat boundary",
                    }]];
                    continue;
                }

                NSMutableArray<NSNumber *> *futureMarkers = [NSMutableArray array];
                for (NSNumber *markerNum in timelineGrid) {
                    double markerSec = [markerNum doubleValue];
                    if (markerSec > clipStart + 0.0001 && markerSec < clipEnd - effectiveMinTrimSeconds + 0.0001) {
                        NSNumber *last = [futureMarkers lastObject];
                        if (!last || fabs([last doubleValue] - markerSec) > (frameSeconds * 0.25)) {
                            [futureMarkers addObject:@(markerSec)];
                        }
                    }
                }

                if (futureMarkers.count == 0) {
                    [plan addObject:[NSMutableDictionary dictionaryWithDictionary:@{
                        @"handle": handle,
                        @"name": name,
                        @"start": @(clipStart),
                        @"end": @(clipEnd),
                        @"status": @"skipped",
                        @"reason": @"No beat boundary falls inside the current clip range",
                    }]];
                    continue;
                }

                double targetSec = 0.0;
                if (randomize) {
                    NSInteger lastIndex = (NSInteger)futureMarkers.count - 1;
                    NSInteger minDistanceFromEnd = MAX(1, randomMinStep);
                    NSInteger maxDistanceFromEnd = MAX(minDistanceFromEnd, randomMaxStep);
                    NSInteger minIndex = MAX(0, lastIndex - maxDistanceFromEnd + 1);
                    NSInteger maxIndex = MAX(0, lastIndex - minDistanceFromEnd + 1);
                    if (maxIndex < minIndex) maxIndex = minIndex;
                    NSMutableArray<NSNumber *> *eligible = [NSMutableArray array];
                    for (NSInteger idx = minIndex; idx <= maxIndex; idx++) {
                        double candidate = [futureMarkers[idx] doubleValue];
                        double newDuration = candidate - clipStart;
                        double trimAmount = clipEnd - candidate;
                        if (newDuration >= effectiveMinResultDuration && trimAmount >= effectiveMinTrimSeconds) {
                            [eligible addObject:@(candidate)];
                        }
                    }
                    if (eligible.count == 0) {
                        [plan addObject:[NSMutableDictionary dictionaryWithDictionary:@{
                            @"handle": handle,
                            @"name": name,
                            @"start": @(clipStart),
                            @"end": @(clipEnd),
                            @"status": @"skipped",
                            @"reason": @"No random beat candidate satisfied the duration constraints",
                        }]];
                        continue;
                    }
                    uint64_t next = SpliceKit_nextRandom(&rngState);
                    targetSec = [eligible[(NSUInteger)(next % eligible.count)] doubleValue];
                } else {
                    BOOL found = NO;
                    for (NSInteger idx = (NSInteger)futureMarkers.count - 1; idx >= 0; idx--) {
                        NSNumber *candidateNum = futureMarkers[(NSUInteger)idx];
                        double candidate = [candidateNum doubleValue];
                        double newDuration = candidate - clipStart;
                        double trimAmount = clipEnd - candidate;
                        if (newDuration >= effectiveMinResultDuration && trimAmount >= effectiveMinTrimSeconds) {
                            targetSec = candidate;
                            found = YES;
                            break;
                        }
                    }
                    if (!found) {
                        [plan addObject:[NSMutableDictionary dictionaryWithDictionary:@{
                            @"handle": handle,
                            @"name": name,
                            @"start": @(clipStart),
                            @"end": @(clipEnd),
                            @"status": @"skipped",
                            @"reason": @"The available beat boundaries would create a clip that is too short",
                        }]];
                        continue;
                    }
                }

                double trimAmount = clipEnd - targetSec;
                [plan addObject:[NSMutableDictionary dictionaryWithDictionary:@{
                    @"handle": handle,
                    @"name": name,
                    @"start": @(clipStart),
                    @"end": @(clipEnd),
                    @"targetEnd": @(targetSec),
                    @"oldDuration": @(currentDuration),
                    @"newDuration": @(targetSec - clipStart),
                    @"trimAmount": @(trimAmount),
                    @"status": @"planned",
                    @"item": entry[@"item"],
                }]];
                planned++;
            }

            NSUInteger applied = 0;
            SEL trimSel = NSSelectorFromString(
                @"operationTrimEdit:endEdits:edgeType:byDelta:trimCommand:trimFlags:temporalResolutionMode:animationHint:error:");
            if (!dryRun && planned > 0 && [sequence respondsToSelector:trimSel]) {
                if ([sequence respondsToSelector:@selector(beginEditing)]) {
                    ((void (*)(id, SEL))objc_msgSend)(sequence, @selector(beginEditing));
                }

                NSMethodSignature *sig = [sequence methodSignatureForSelector:trimSel];
                for (NSMutableDictionary *entry in plan) {
                    if (![entry[@"status"] isEqualToString:@"planned"]) continue;

                    id item = entry[@"item"];
                    NSArray *clipArray = @[item];
                    id nilValue = nil;
                    int edgeType = 0;
                    int trimCommand = 1;
                    int trimFlags = 2;
                    int temporalRes = 0;
                    id animHint = nil;
                    void *errorPtr = NULL;
                    double trimAmount = [entry[@"trimAmount"] doubleValue];
                    SpliceKit_CMTime delta = SpliceKit_buildCMTime(-trimAmount, timeline);

                    BOOL ok = NO;
                    @try {
                        NSInvocation *inv = [NSInvocation invocationWithMethodSignature:sig];
                        [inv setTarget:sequence];
                        [inv setSelector:trimSel];
                        [inv setArgument:&nilValue atIndex:2];
                        [inv setArgument:&clipArray atIndex:3];
                        [inv setArgument:&edgeType atIndex:4];
                        [inv setArgument:&delta atIndex:5];
                        [inv setArgument:&trimCommand atIndex:6];
                        [inv setArgument:&trimFlags atIndex:7];
                        [inv setArgument:&temporalRes atIndex:8];
                        [inv setArgument:&animHint atIndex:9];
                        [inv setArgument:&errorPtr atIndex:10];
                        [inv invoke];
                        [inv getReturnValue:&ok];
                    } @catch (NSException *e) {
                        entry[@"status"] = @"failed";
                        entry[@"reason"] = e.reason ?: @"trim invocation failed";
                    }

                    if (ok) {
                        entry[@"status"] = @"applied";
                        applied++;
                    } else if (!entry[@"reason"]) {
                        entry[@"status"] = @"failed";
                        entry[@"reason"] = @"operationTrimEdit returned NO";
                    }
                    [entry removeObjectForKey:@"item"];
                }

                if ([sequence respondsToSelector:@selector(endEditing)]) {
                    ((void (*)(id, SEL))objc_msgSend)(sequence, @selector(endEditing));
                }
            } else {
                for (NSMutableDictionary *entry in plan) {
                    [entry removeObjectForKey:@"item"];
                }
            }

            NSMutableArray *gridPreview = [NSMutableArray array];
            NSUInteger previewCount = MIN((NSUInteger)12, timelineGrid.count);
            for (NSUInteger i = 0; i < previewCount; i++) {
                [gridPreview addObject:timelineGrid[i]];
            }

            result = @{
                @"status": @"ok",
                @"dryRun": @(dryRun),
                @"grid": grid,
                @"targetMode": targetMode,
                @"randomize": @(randomize),
                @"randomSeed": @(randomSeed),
                @"source": @{
                    @"handle": SpliceKit_storeHandle(sourceItem),
                    @"name": sourceEntry[@"name"] ?: @"",
                    @"start": @(sourceStartSec),
                    @"end": @(sourceEndSec),
                    @"tempo": @(tempo),
                    @"beatGridEnabled": sourceEntry[@"beatGridEnabled"] ?: @NO,
                },
                @"gridPointCount": @(timelineGrid.count),
                @"gridPreview": gridPreview,
                @"targetCount": @(targetEntries.count),
                @"planned": @(planned),
                @"applied": @(applied),
                @"plan": plan,
            };
        } @catch (NSException *e) {
            result = @{@"error": [NSString stringWithFormat:@"Exception: %@", e.reason]};
        }
    });
    return result ?: @{@"error": @"Failed to trim clips to beats"};
}

// Batch timeline/playback actions executed server-side (no per-action round-trip)
static NSDictionary *SpliceKit_handleBatchActions(NSDictionary *params) {
    NSArray *actions = params[@"actions"];
    if (!actions || ![actions isKindOfClass:[NSArray class]] || actions.count == 0) {
        return @{@"error": @"actions array required"};
    }

    __block NSDictionary *result = nil;
    SpliceKit_executeOnMainThread(^{
        @try {
            NSMutableArray *results = [NSMutableArray array];
            NSUInteger executed = 0;

            for (NSDictionary *act in actions) {
                NSString *type = act[@"type"] ?: @"timeline";
                NSString *actionName = act[@"action"] ?: @"";
                NSInteger repeat = [act[@"repeat"] integerValue];
                if (repeat < 1) repeat = 1;

                if ([type isEqualToString:@"wait"]) {
                    double secs = [act[@"seconds"] doubleValue];
                    if (secs <= 0) secs = 0.5;
                    [NSThread sleepForTimeInterval:secs];
                    [results addObject:[NSString stringWithFormat:@"wait %.2fs", secs]];
                } else if ([type isEqualToString:@"playback"]) {
                    for (NSInteger i = 0; i < repeat; i++) {
                        SpliceKit_handlePlayback(@{@"action": actionName});
                    }
                    [results addObject:[NSString stringWithFormat:@"playback.%@%@",
                        actionName, repeat > 1 ? [NSString stringWithFormat:@" x%ld", (long)repeat] : @""]];
                } else if ([type isEqualToString:@"timeline"]) {
                    for (NSInteger i = 0; i < repeat; i++) {
                        SpliceKit_handleTimelineAction(@{@"action": actionName});
                    }
                    [results addObject:[NSString stringWithFormat:@"timeline.%@%@",
                        actionName, repeat > 1 ? [NSString stringWithFormat:@" x%ld", (long)repeat] : @""]];
                } else if ([type isEqualToString:@"seek"]) {
                    double secs = [act[@"seconds"] doubleValue];
                    SpliceKit_handlePlaybackSeek(@{@"seconds": @(secs)});
                    [results addObject:[NSString stringWithFormat:@"seek %.2fs", secs]];
                } else {
                    [results addObject:[NSString stringWithFormat:@"unknown type: %@", type]];
                    continue;
                }
                executed++;
            }

            result = @{
                @"status": @"ok",
                @"executed": @(executed),
                @"results": results,
            };
        } @catch (NSException *e) {
            result = @{@"error": [NSString stringWithFormat:@"Exception: %@", e.reason]};
        }
    });
    return result ?: @{@"error": @"Failed to execute batch actions"};
}

static NSDictionary *SpliceKit_handleSetRange(NSDictionary *params) {
    NSNumber *startSec = params[@"startSeconds"];
    NSNumber *endSec = params[@"endSeconds"];
    if (!startSec || !endSec) {
        return @{@"error": @"startSeconds and endSeconds parameters required"};
    }

    __block NSDictionary *result = nil;
    SpliceKit_executeOnMainThread(^{
        @try {
            id timeline = SpliceKit_getActiveTimelineModule();
            if (!timeline) {
                result = @{@"error": @"No active timeline module"};
                return;
            }

            double startVal = [startSec doubleValue];
            double endVal = [endSec doubleValue];

            // Build CMTimes
            SpliceKit_CMTime startTime = SpliceKit_buildCMTime(startVal, timeline);
            SpliceKit_CMTime endTime = SpliceKit_buildCMTime(endVal, timeline);

            // Seek to start, mark in
            BOOL inOk = SpliceKit_seekAndMark(timeline, startTime, @"setRangeStart:");
            // Seek to end, mark out
            BOOL outOk = SpliceKit_seekAndMark(timeline, endTime, @"setRangeEnd:");

            result = @{
                @"status": @"ok",
                @"startSeconds": @(startVal),
                @"endSeconds": @(endVal),
                @"rangeStartSet": @(inOk),
                @"rangeEndSet": @(outOk),
            };
        } @catch (NSException *e) {
            result = @{@"error": [NSString stringWithFormat:@"Exception: %@", e.reason]};
        }
    });
    return result ?: @{@"error": @"Failed to set range"};
}

// Helper: collect exportable clips with their time ranges (no ARC-managed ObjC objects in the mix)
static NSArray *SpliceKit_collectExportableClips(id primaryObj, NSSet *selectedSet) {
    SEL erSel = NSSelectorFromString(@"effectiveRangeOfObject:");
    if (![primaryObj respondsToSelector:erSel]) return nil;

    NSArray *allItems = ((id (*)(id, SEL))objc_msgSend)(primaryObj, @selector(containedItems));
    if (![allItems isKindOfClass:[NSArray class]]) return nil;

    Class transitionClass = objc_getClass("FFAnchoredTransition");
    NSMutableArray *clips = [NSMutableArray array];

    for (id item in allItems) {
        if (transitionClass && [item isKindOfClass:transitionClass]) continue;
        NSString *className = NSStringFromClass([item class]);
        if ([className containsString:@"Gap"]) continue;
        if (selectedSet && ![selectedSet containsObject:item]) continue;

        @try {
            SpliceKit_CMTimeRange range = ((SpliceKit_CMTimeRange (*)(id, SEL, id))STRET_MSG)(
                primaryObj, erSel, item);
            NSString *name = @"Untitled";
            if ([item respondsToSelector:@selector(displayName)]) {
                id n = ((id (*)(id, SEL))objc_msgSend)(item, @selector(displayName));
                if (n) name = n;
            }
            SpliceKit_CMTime endTime = range.start;
            if (range.duration.timescale == range.start.timescale) {
                endTime.value = range.start.value + range.duration.value;
            } else if (range.duration.timescale > 0) {
                endTime.value = range.start.value +
                    (range.duration.value * range.start.timescale / range.duration.timescale);
            }
            [clips addObject:@{
                @"name": name,
                @"startTime": SpliceKit_serializeCMTime(range.start),
                @"endTime": SpliceKit_serializeCMTime(endTime),
                @"startCMTime": [NSValue valueWithBytes:&range.start objCType:@encode(SpliceKit_CMTime)],
                @"endCMTime": [NSValue valueWithBytes:&endTime objCType:@encode(SpliceKit_CMTime)],
            }];
        } @catch (NSException *e) { /* skip */ }
    }
    return clips;
}

// --- Batch Export: swizzle approach ---
// We swizzle FFSequenceExporter's showSharePanelWithSources:... to skip the modal dialog
// and directly queue the export. The original method creates a share panel, runs it modally,
// then queues batches. Our replacement creates the panel silently, extracts batches, and queues.

static NSURL *sBatchExportFolderURL = nil;
static NSString *sBatchExportFileName = nil;
static BOOL sBatchExportActive = NO;
static IMP sOrigShowSharePanel = NULL;
static NSInteger sBatchExportPendingCount = 0; // tracks async exports still running
static SpliceKit_CMTime sBatchExportClipStart;
static SpliceKit_CMTime sBatchExportClipEnd;

// Swizzle NSWorkspace openURL: to suppress auto-open of exported files
static IMP sOrigOpenURL = NULL;
static BOOL SpliceKit_swizzled_openURL(id self, SEL _cmd, id url) {
    if (sBatchExportPendingCount > 0 && url && [url isKindOfClass:[NSURL class]]) {
        // Suppress opening files from the batch export folder
        NSString *path = [(NSURL *)url path];
        NSString *folderPath = [sBatchExportFolderURL path];
        if (folderPath && [path hasPrefix:folderPath]) {
            SpliceKit_log(@"[BatchExport] Suppressed auto-open: %@", path);
            sBatchExportPendingCount--;
            return YES; // pretend we opened it
        }
    }
    // Call original
    return sOrigOpenURL ? ((BOOL (*)(id, SEL, id))sOrigOpenURL)(self, _cmd, url) : NO;
}

// Also suppress activateFileViewerSelectingURLs: (Reveal in Finder)
static IMP sOrigRevealURLs = NULL;
static void SpliceKit_swizzled_revealURLs(id self, SEL _cmd, id urls) {
    if (sBatchExportPendingCount > 0 && urls) {
        SpliceKit_log(@"[BatchExport] Suppressed reveal in Finder");
        return;
    }
    if (sOrigRevealURLs) ((void (*)(id, SEL, id))sOrigRevealURLs)(self, _cmd, urls);
}

// Suppress openURL:configuration:completionHandler: (modern API)
static IMP sOrigOpenURLConfig = NULL;
static void SpliceKit_swizzled_openURLConfig(id self, SEL _cmd, id url, id config, id handler) {
    if (sBatchExportPendingCount > 0 && url && [url isKindOfClass:[NSURL class]]) {
        NSString *path = [(NSURL *)url path];
        NSString *folderPath = [sBatchExportFolderURL path];
        if (folderPath && [path hasPrefix:folderPath]) {
            SpliceKit_log(@"[BatchExport] Suppressed openURL:config: %@", path);
            sBatchExportPendingCount--;
            if (handler) ((void (^)(id, id))handler)(nil, nil);
            return;
        }
    }
    if (sOrigOpenURLConfig) ((void (*)(id, SEL, id, id, id))sOrigOpenURLConfig)(self, _cmd, url, config, handler);
}

// Suppress openURLs:withApplicationAtURL:configuration:completionHandler:
static IMP sOrigOpenURLs = NULL;
static void SpliceKit_swizzled_openURLs(id self, SEL _cmd, id urls, id appURL, id config, id handler) {
    if (sBatchExportPendingCount > 0 && urls) {
        SpliceKit_log(@"[BatchExport] Suppressed openURLs: batch");
        sBatchExportPendingCount--;
        if (handler) ((void (^)(id, id))handler)(nil, nil);
        return;
    }
    if (sOrigOpenURLs) ((void (*)(id, SEL, id, id, id, id))sOrigOpenURLs)(self, _cmd, urls, appURL, config, handler);
}

// Suppress openFile: (deprecated but still used)
static IMP sOrigOpenFile = NULL;
static BOOL SpliceKit_swizzled_openFile(id self, SEL _cmd, id path) {
    if (sBatchExportPendingCount > 0 && path) {
        NSString *folderPath = [sBatchExportFolderURL path];
        if (folderPath && [(NSString *)path hasPrefix:folderPath]) {
            sBatchExportPendingCount--;
            return YES;
        }
    }
    return sOrigOpenFile ? ((BOOL (*)(id, SEL, id))sOrigOpenFile)(self, _cmd, path) : NO;
}

// Replacement for -[FFSequenceExporter showSharePanelWithSources:destination:destinationURL:parentWindow:]
// Called after shareToDestination:parentWindow: has already converted sources to CK format
static void SpliceKit_swizzled_showSharePanel(id self, SEL _cmd, id sources, id dest, id destURL, id parentWindow) {
    if (!sBatchExportActive) {
        // Not in batch mode - call original
        if (sOrigShowSharePanel) {
            ((void (*)(id, SEL, id, id, id, id))sOrigShowSharePanel)(self, _cmd, sources, dest, destURL, parentWindow);
        }
        return;
    }

    SpliceKit_log(@"[BatchExport] Swizzled showSharePanel called with %@ sources, dest=%@",
        sources ? @([(NSArray *)sources count]) : @"nil", NSStringFromClass([dest class]));

    @try {
        // Determine panel class (consumer vs pro)
        BOOL isConsumer = ((BOOL (*)(id, SEL))objc_msgSend)(
            objc_getClass("Flexo"), NSSelectorFromString(@"isConsumerUI"));

        Class panelClass = isConsumer
            ? objc_getClass("FFConsumerSharePanel")
            : objc_getClass("FFSharePanel");
        if (!panelClass) panelClass = objc_getClass("FFBaseSharePanel");

        // Modify source to set clip-specific in/out range
        id firstSource = [(NSArray *)sources firstObject];
        id sourceToUse = firstSource;

        SEL mutableCopySel = @selector(mutableCopy);
        SEL setInOutSel = NSSelectorFromString(@"setInPoint:outPoint:");
        if (firstSource && [firstSource respondsToSelector:mutableCopySel] &&
            sBatchExportClipStart.flags == 1 && sBatchExportClipEnd.flags == 1) {
            // Create a mutable copy and set the clip's range as in/out points
            sourceToUse = ((id (*)(id, SEL))objc_msgSend)(firstSource, mutableCopySel);
            if (sourceToUse && [sourceToUse respondsToSelector:setInOutSel]) {
                // Convert our CMTime to NSValue objects that the source expects
                // The source's setInPoint:outPoint: takes CMTime-wrapping objects
                // Let's try creating PCTimeObject or similar
                SEL inPtSel = NSSelectorFromString(@"inPoint");
                id origIn = [firstSource respondsToSelector:inPtSel]
                    ? ((id (*)(id, SEL))objc_msgSend)(firstSource, inPtSel) : nil;
                SpliceKit_log(@"[BatchExport] Original inPoint: %@ (class: %@)",
                    origIn, origIn ? NSStringFromClass([origIn class]) : @"nil");

                // Try creating time objects from our CMTime values
                // PCTimeObject or similar wraps CMTime
                Class timeObjClass = objc_getClass("PCTimeObject");
                if (timeObjClass) {
                    SEL initWithTimeSel = NSSelectorFromString(@"timeObjectWithCMTime:");
                    if ([(id)timeObjClass respondsToSelector:initWithTimeSel]) {
                        id startObj = ((id (*)(id, SEL, SpliceKit_CMTime))objc_msgSend)(
                            (id)timeObjClass, initWithTimeSel, sBatchExportClipStart);
                        id endObj = ((id (*)(id, SEL, SpliceKit_CMTime))objc_msgSend)(
                            (id)timeObjClass, initWithTimeSel, sBatchExportClipEnd);
                        if (startObj && endObj) {
                            ((void (*)(id, SEL, id, id))objc_msgSend)(sourceToUse, setInOutSel, startObj, endObj);
                            SpliceKit_log(@"[BatchExport] Set in/out: %@ - %@", startObj, endObj);
                        }
                    }
                }
            }
        }

        // Create the panel silently (no runModal)
        id panel = nil;
        void *rawError = NULL;

        if (isConsumer) {
            SEL createSel = NSSelectorFromString(@"sharePanelWithSource:destination:error:");
            panel = ((id (*)(id, SEL, id, id, void **))objc_msgSend)(
                (id)panelClass, createSel, sourceToUse, dest, &rawError);
        } else {
            NSArray *modSources = @[sourceToUse];
            SEL createSel = NSSelectorFromString(@"sharePanelWithSources:destination:error:");
            panel = ((id (*)(id, SEL, id, id, void **))objc_msgSend)(
                (id)panelClass, createSel, modSources, dest, &rawError);
        }

        if (!panel) {
            id panelError = rawError ? (__bridge id)rawError : nil;
            SpliceKit_log(@"[BatchExport] Panel creation failed: %@",
                panelError ? ((id (*)(id, SEL))objc_msgSend)(panelError, @selector(localizedDescription)) : @"nil");
            return;
        }

        // Set destination URL to our batch export folder
        NSURL *outputFolderURL = sBatchExportFolderURL ?: (NSURL *)destURL;
        SEL setURLSel = NSSelectorFromString(@"setDestinationURL:");
        if ([panel respondsToSelector:setURLSel]) {
            ((void (*)(id, SEL, id))objc_msgSend)(panel, setURLSel, outputFolderURL);
        }

        // Set delegate (the exporter itself, needed for queuing)
        SEL setDelegateSel = NSSelectorFromString(@"setDelegate:");
        if ([panel respondsToSelector:setDelegateSel]) {
            ((void (*)(id, SEL, id))objc_msgSend)(panel, setDelegateSel, self);
        }

        // Get batches (created during panel init)
        NSArray *batches = ((id (*)(id, SEL))objc_msgSend)(panel, NSSelectorFromString(@"batches"));
        SpliceKit_log(@"[BatchExport] Panel created %lu batches", (unsigned long)(batches ? batches.count : 0));

        if (!batches || batches.count == 0) {
            SpliceKit_log(@"[BatchExport] No batches from panel");
            return;
        }

        // Set per-clip filename on targets if provided
        if (sBatchExportFileName && sBatchExportFolderURL) {
            NSURL *fileURL = [sBatchExportFolderURL URLByAppendingPathComponent:sBatchExportFileName];
            for (id batch in batches) {
                id jobs = ((id (*)(id, SEL))objc_msgSend)(batch, NSSelectorFromString(@"jobs"));
                if (!jobs || ![jobs isKindOfClass:[NSArray class]]) continue;
                for (id job in jobs) {
                    id targets = ((id (*)(id, SEL))objc_msgSend)(job, NSSelectorFromString(@"targets"));
                    if (!targets || ![targets isKindOfClass:[NSArray class]]) continue;
                    for (id target in targets) {
                        if ([target respondsToSelector:NSSelectorFromString(@"setDestinationURL:")]) {
                            ((void (*)(id, SEL, id))objc_msgSend)(target,
                                NSSelectorFromString(@"setDestinationURL:"), fileURL);
                        }
                    }
                }
            }
        }

        // Queue the export operations directly (no dialog!)
        SEL queueSel = NSSelectorFromString(@"queueShareOperationsForBatches:addToTheater:");
        if ([self respondsToSelector:queueSel]) {
            SpliceKit_log(@"[BatchExport] Queuing batches on %@", NSStringFromClass([self class]));
            ((void (*)(id, SEL, id, BOOL))objc_msgSend)(self, queueSel, batches, NO);
            SpliceKit_log(@"[BatchExport] Queued successfully!");
        } else {
            SpliceKit_log(@"[BatchExport] Exporter doesn't respond to queueShareOperationsForBatches:");
        }
    } @catch (NSException *e) {
        SpliceKit_log(@"[BatchExport] Exception in swizzled showSharePanel: %@", e.reason);
    }
}

// Unused - kept for reference
static NSString *SpliceKit_queueClipExport(id timeline, SpliceKit_CMTime startTime, SpliceKit_CMTime endTime,
                                            NSURL *fileURL, id dest) {
    // Set range for this clip
    SpliceKit_seekAndMark(timeline, startTime, @"setRangeStart:");
    SpliceKit_seekAndMark(timeline, endTime, @"setRangeEnd:");

    // Get sources for this range via shareSelection:
    SEL selSel = NSSelectorFromString(@"shareSelection:");
    if (![timeline respondsToSelector:selSel]) return @"no shareSelection: method";

    void *rawSources = ((void * (*)(id, SEL, id))objc_msgSend)(timeline, selSel, nil);
    if (!rawSources) return @"no sources for range";

    id sources = (__bridge id)rawSources;
    SpliceKit_log(@"[BatchExport] shareSelection: returned %@ (class: %@)", sources, NSStringFromClass([sources class]));

    if (![sources isKindOfClass:[NSArray class]]) {
        return [NSString stringWithFormat:@"sources not array, got %@", NSStringFromClass([sources class])];
    }
    NSUInteger sourceCount = [(NSArray *)sources count];
    if (sourceCount == 0) return @"empty sources";
    SpliceKit_log(@"[BatchExport] Got %lu sources", (unsigned long)sourceCount);

    // Create share panel silently to build CK batch objects
    Class panelClass = objc_getClass("FFConsumerSharePanel")
        ?: objc_getClass("FFSharePanel")
        ?: objc_getClass("FFBaseSharePanel");
    if (!panelClass) return @"no share panel class";
    SpliceKit_log(@"[BatchExport] Using panel class: %@", NSStringFromClass(panelClass));

    SEL createSel = NSSelectorFromString(@"sharePanelWithSource:destination:error:");
    if (![(id)panelClass respondsToSelector:createSel]) return @"panel class has no create method";

    id firstSource = [(NSArray *)sources firstObject];
    SpliceKit_log(@"[BatchExport] First source: %@ (class: %@)", firstSource, NSStringFromClass([firstSource class]));

    __unsafe_unretained id panelError = nil;
    void *rawPanel = ((void * (*)(id, SEL, id, id, __unsafe_unretained id *))objc_msgSend)(
        (id)panelClass, createSel, firstSource, dest, &panelError);
    if (!rawPanel) {
        NSString *errStr = panelError
            ? [NSString stringWithFormat:@"panel: %@",
               ((id (*)(id, SEL))objc_msgSend)(panelError, @selector(localizedDescription))]
            : @"panel creation returned nil";
        SpliceKit_log(@"[BatchExport] %@", errStr);
        return errStr;
    }
    id panel = (__bridge id)rawPanel;
    SpliceKit_log(@"[BatchExport] Panel created: %@", NSStringFromClass([panel class]));

    // Set destination URL
    SEL setURLSel = NSSelectorFromString(@"setDestinationURL:");
    if ([panel respondsToSelector:setURLSel]) {
        ((void (*)(id, SEL, id))objc_msgSend)(panel, setURLSel, [fileURL URLByDeletingLastPathComponent]);
    }

    // Extract batches
    SEL batchesSel = NSSelectorFromString(@"batches");
    if (![panel respondsToSelector:batchesSel]) return @"panel has no batches method";
    NSArray *batches = ((id (*)(id, SEL))objc_msgSend)(panel, batchesSel);
    if (!batches || ![batches isKindOfClass:[NSArray class]]) {
        SpliceKit_log(@"[BatchExport] batches returned: %@ (class: %@)", batches, batches ? NSStringFromClass([batches class]) : @"nil");
        return @"no batches";
    }
    SpliceKit_log(@"[BatchExport] Got %lu batches", (unsigned long)batches.count);
    if (batches.count == 0) return @"zero batches";

    // Log batch structure
    for (NSUInteger bi = 0; bi < batches.count; bi++) {
        id batch = batches[bi];
        SpliceKit_log(@"[BatchExport] Batch %lu: %@ (class: %@)", (unsigned long)bi, batch, NSStringFromClass([batch class]));
        SEL jobsSel = NSSelectorFromString(@"jobs");
        if ([batch respondsToSelector:jobsSel]) {
            NSArray *jobs = ((id (*)(id, SEL))objc_msgSend)(batch, jobsSel);
            SpliceKit_log(@"[BatchExport]   Jobs: %lu", (unsigned long)(jobs ? [(NSArray *)jobs count] : 0));
            if (jobs && [jobs isKindOfClass:[NSArray class]]) {
                for (id job in jobs) {
                    SEL targetsSel = NSSelectorFromString(@"targets");
                    if ([job respondsToSelector:targetsSel]) {
                        NSArray *targets = ((id (*)(id, SEL))objc_msgSend)(job, targetsSel);
                        SpliceKit_log(@"[BatchExport]     Targets: %lu", (unsigned long)(targets ? [(NSArray *)targets count] : 0));
                        if (targets && [targets isKindOfClass:[NSArray class]]) {
                            for (id target in targets) {
                                // Set destination URL on target
                                SEL setDestSel = NSSelectorFromString(@"setDestinationURL:");
                                if ([target respondsToSelector:setDestSel]) {
                                    ((void (*)(id, SEL, id))objc_msgSend)(target, setDestSel, fileURL);
                                    SpliceKit_log(@"[BatchExport]     Set target URL: %@", fileURL);
                                }
                                // Log output URLs
                                SEL outSel = NSSelectorFromString(@"outputURLs");
                                if ([target respondsToSelector:outSel]) {
                                    id urls = ((id (*)(id, SEL))objc_msgSend)(target, outSel);
                                    SpliceKit_log(@"[BatchExport]     Output URLs: %@", urls);
                                }
                            }
                        }
                    }
                }
            }
        }
    }

    // Create exporter and queue
    Class exporterClass = objc_getClass("FFSequenceExporter");
    SEL expSel = NSSelectorFromString(@"sequenceExporterWithSelection:useTimelinePlayback:");
    if (!exporterClass || ![(id)exporterClass respondsToSelector:expSel]) return @"no exporter class";

    void *rawExporter = ((void * (*)(id, SEL, id, id))objc_msgSend)(
        (id)exporterClass, expSel, sources, nil);
    if (!rawExporter) return @"exporter creation failed";
    id exporter = (__bridge id)rawExporter;
    SpliceKit_log(@"[BatchExport] Exporter: %@", NSStringFromClass([exporter class]));

    SEL queueSel = NSSelectorFromString(@"queueShareOperationsForBatches:addToTheater:");
    if (![exporter respondsToSelector:queueSel]) return @"exporter has no queue method";

    SpliceKit_log(@"[BatchExport] Queuing %lu batches...", (unsigned long)batches.count);
    ((void (*)(id, SEL, id, BOOL))objc_msgSend)(exporter, queueSel, batches, NO);
    SpliceKit_log(@"[BatchExport] Queued successfully");
    return @"queued";
}

NSDictionary *SpliceKit_handleBatchExport(NSDictionary *params) {
    NSString *scope = params[@"scope"] ?: @"all";
    NSString *folderPath = params[@"folder"];

    __block NSDictionary *result = nil;
    SpliceKit_executeOnMainThread(^{
        @try {
            id timeline = SpliceKit_getActiveTimelineModule();
            if (!timeline) { result = @{@"error": @"No active timeline module"}; return; }

            id sequence = ((id (*)(id, SEL))objc_msgSend)(timeline, @selector(sequence));
            if (!sequence) { result = @{@"error": @"No sequence in timeline"}; return; }

            id primaryObj = [sequence respondsToSelector:@selector(primaryObject)]
                ? ((id (*)(id, SEL))objc_msgSend)(sequence, @selector(primaryObject)) : nil;
            if (!primaryObj) { result = @{@"error": @"Cannot access primary storyline"}; return; }

            // Show folder picker
            NSURL *folderURL = nil;
            if (folderPath) {
                folderURL = [NSURL fileURLWithPath:folderPath];
            } else {
                NSOpenPanel *openPanel = [NSOpenPanel openPanel];
                openPanel.canChooseFiles = NO;
                openPanel.canChooseDirectories = YES;
                openPanel.canCreateDirectories = YES;
                openPanel.prompt = @"Export Here";
                openPanel.message = @"Choose destination folder for batch export";
                NSModalResponse resp = [openPanel runModal];
                if (resp != NSModalResponseOK) { result = @{@"status": @"cancelled"}; return; }
                folderURL = openPanel.URL;
            }
            if (!folderURL) { result = @{@"error": @"No folder selected"}; return; }
            [[NSFileManager defaultManager] createDirectoryAtURL:folderURL
                                     withIntermediateDirectories:YES attributes:nil error:nil];

            // Get selected set if needed
            NSSet *selectedSet = nil;
            if ([scope isEqualToString:@"selected"]) {
                SEL selSel = NSSelectorFromString(@"selectedItems:includeItemBeforePlayheadIfLast:");
                if ([timeline respondsToSelector:selSel]) {
                    id sel = ((id (*)(id, SEL, BOOL, BOOL))objc_msgSend)(timeline, selSel, NO, NO);
                    if ([sel isKindOfClass:[NSArray class]]) selectedSet = [NSSet setWithArray:sel];
                }
                if (!selectedSet || selectedSet.count == 0) {
                    result = @{@"error": @"No clips selected"}; return;
                }
            }

            // Get default share destination
            Class destClass = objc_getClass("FFShareDestination");
            id dest = destClass ? ((id (*)(id, SEL))objc_msgSend)((id)destClass,
                NSSelectorFromString(@"defaultUserDestination")) : nil;
            if (!dest) { result = @{@"error": @"No default share destination. Configure in File > Share > Add Destination."}; return; }

            // Collect clips
            NSArray *clips = SpliceKit_collectExportableClips(primaryObj, selectedSet);
            if (!clips || clips.count == 0) { result = @{@"error": @"No exportable clips"}; return; }

            // Install swizzle on FFSequenceExporter to bypass share dialog
            Class exporterClass = objc_getClass("FFSequenceExporter");
            SEL showPanelSel = NSSelectorFromString(@"showSharePanelWithSources:destination:destinationURL:parentWindow:");
            Method origMethod = exporterClass ? class_getInstanceMethod(exporterClass, showPanelSel) : NULL;

            if (!origMethod) {
                result = @{@"error": @"Cannot find showSharePanelWithSources: method on FFSequenceExporter"};
                return;
            }

            // Save original and install swizzle
            sOrigShowSharePanel = method_getImplementation(origMethod);
            method_setImplementation(origMethod, (IMP)SpliceKit_swizzled_showSharePanel);
            sBatchExportActive = YES;
            sBatchExportFolderURL = folderURL;
            sBatchExportPendingCount = clips.count;

            // Swizzle NSWorkspace methods to suppress auto-open of exported files
            Class wsClass = [NSWorkspace class];
            Method m;
            m = class_getInstanceMethod(wsClass, @selector(openURL:));
            if (m && !sOrigOpenURL) { sOrigOpenURL = method_getImplementation(m); method_setImplementation(m, (IMP)SpliceKit_swizzled_openURL); }

            m = class_getInstanceMethod(wsClass, @selector(activateFileViewerSelectingURLs:));
            if (m && !sOrigRevealURLs) { sOrigRevealURLs = method_getImplementation(m); method_setImplementation(m, (IMP)SpliceKit_swizzled_revealURLs); }

            m = class_getInstanceMethod(wsClass, NSSelectorFromString(@"openURL:configuration:completionHandler:"));
            if (m && !sOrigOpenURLConfig) { sOrigOpenURLConfig = method_getImplementation(m); method_setImplementation(m, (IMP)SpliceKit_swizzled_openURLConfig); }

            m = class_getInstanceMethod(wsClass, NSSelectorFromString(@"openURLs:withApplicationAtURL:configuration:completionHandler:"));
            if (m && !sOrigOpenURLs) { sOrigOpenURLs = method_getImplementation(m); method_setImplementation(m, (IMP)SpliceKit_swizzled_openURLs); }

            m = class_getInstanceMethod(wsClass, @selector(openFile:));
            if (m && !sOrigOpenFile) { sOrigOpenFile = method_getImplementation(m); method_setImplementation(m, (IMP)SpliceKit_swizzled_openFile); }

            // Set destination action to "Save only" (no auto-open)
            SEL actionSel = NSSelectorFromString(@"action");
            SEL setActionSel = NSSelectorFromString(@"setAction:");
            id origAction = nil;
            if ([dest respondsToSelector:actionSel]) {
                origAction = ((id (*)(id, SEL))objc_msgSend)(dest, actionSel);
            }
            if ([dest respondsToSelector:setActionSel]) {
                ((void (*)(id, SEL, id))objc_msgSend)(dest, setActionSel, nil); // nil = save only
            }

            // Get share helper
            id shareHelper = ((id (*)(id, SEL))objc_msgSend)(timeline, NSSelectorFromString(@"shareHelper"));
            SEL shareSel = NSSelectorFromString(@"_shareToDestination:isDefault:");

            NSMutableArray *exportResults = [NSMutableArray array];
            NSInteger exported = 0;

            for (NSUInteger i = 0; i < clips.count; i++) {
                NSDictionary *clipInfo = clips[i];
                SpliceKit_CMTime startCMTime, endCMTime;
                [clipInfo[@"startCMTime"] getValue:&startCMTime];
                [clipInfo[@"endCMTime"] getValue:&endCMTime];

                NSString *clipName = clipInfo[@"name"];
                NSString *safeName = [[clipName stringByReplacingOccurrencesOfString:@"/" withString:@"-"]
                                      stringByReplacingOccurrencesOfString:@":" withString:@"-"];
                // Use clip name directly; append index only if duplicate
                NSString *baseName = safeName;
                NSString *candidate = baseName;
                NSUInteger dupIdx = 2;
                while ([[NSFileManager defaultManager] fileExistsAtPath:
                        [[folderURL URLByAppendingPathComponent:
                          [candidate stringByAppendingPathExtension:@"mov"]] path]]) {
                    candidate = [NSString stringWithFormat:@"%@ %lu", baseName, (unsigned long)dupIdx++];
                }
                sBatchExportFileName = candidate;

                NSString *status = @"unknown";
                @try {
                    // Store clip range for the swizzled showSharePanel
                    sBatchExportClipStart = startCMTime;
                    sBatchExportClipEnd = endCMTime;

                    // Set in/out range using simulated I/O key presses
                    SpliceKit_seekAndMark(timeline, startCMTime, @"setRangeStart:");
                    SpliceKit_seekAndMark(timeline, endCMTime, @"setRangeEnd:");

                    // Trigger the normal share flow - our swizzle intercepts the dialog
                    if (shareHelper && [shareHelper respondsToSelector:shareSel]) {
                        ((void (*)(id, SEL, id, BOOL))objc_msgSend)(shareHelper, shareSel, nil, YES);
                        status = @"queued";
                        exported++;
                    } else {
                        status = @"no share helper";
                    }
                } @catch (NSException *e) {
                    status = [NSString stringWithFormat:@"error: %@", e.reason];
                }

                // Let FCP process events between clips
                [[NSRunLoop currentRunLoop] runUntilDate:[NSDate dateWithTimeIntervalSinceNow:0.1]];

                [exportResults addObject:@{
                    @"name": clipName,
                    @"startTime": clipInfo[@"startTime"],
                    @"endTime": clipInfo[@"endTime"],
                    @"status": status,
                }];
            }

            // Restore showSharePanel swizzle
            if (origMethod && sOrigShowSharePanel) {
                method_setImplementation(origMethod, sOrigShowSharePanel);
            }
            sBatchExportActive = NO;
            sBatchExportFileName = nil;
            sBatchExportFolderURL = nil;
            sOrigShowSharePanel = NULL;

            // Restore original destination action
            if ([dest respondsToSelector:setActionSel] && origAction) {
                ((void (*)(id, SEL, id))objc_msgSend)(dest, setActionSel, origAction);
            }

            // Clear range
            id app = ((id (*)(id, SEL))objc_msgSend)(
                objc_getClass("NSApplication"), @selector(sharedApplication));
            ((BOOL (*)(id, SEL, SEL, id, id))objc_msgSend)(
                app, @selector(sendAction:to:from:),
                NSSelectorFromString(@"clearRange:"), nil, nil);

            result = @{
                @"status": @"ok",
                @"folder": [folderURL path] ?: @"",
                @"exported": @(exported),
                @"total": @(clips.count),
                @"clips": exportResults,
            };
        } @catch (NSException *e) {
            result = @{@"error": [NSString stringWithFormat:@"Exception: %@", e.reason]};
        }
    });
    return result ?: @{@"error": @"Failed to batch export"};
}

static NSDictionary *SpliceKit_handleTimelineGetState(NSDictionary *params) {
    __block NSDictionary *result = nil;

    SpliceKit_executeOnMainThread(^{
        @try {
            id timeline = SpliceKit_getActiveTimelineModule();
            if (!timeline) {
                result = @{@"error": @"No active timeline module"};
                return;
            }

            NSMutableDictionary *state = [NSMutableDictionary dictionary];

            // Get sequence
            SEL seqSel = @selector(sequence);
            if ([timeline respondsToSelector:seqSel]) {
                id sequence = ((id (*)(id, SEL))objc_msgSend)(timeline, seqSel);
                if (sequence) {
                    state[@"sequence"] = [sequence description];
                    state[@"sequenceClass"] = NSStringFromClass([sequence class]);

                    // Get contained items count
                    SEL ciSel = @selector(containedItems);
                    if ([sequence respondsToSelector:ciSel]) {
                        id items = ((id (*)(id, SEL))objc_msgSend)(sequence, ciSel);
                        if ([items respondsToSelector:@selector(count)]) {
                            state[@"itemCount"] = @([(NSArray *)items count]);
                        }
                        // Describe each item
                        if ([items respondsToSelector:@selector(objectEnumerator)]) {
                            NSMutableArray *itemDescs = [NSMutableArray array];
                            for (id item in (NSArray *)items) {
                                NSMutableDictionary *desc = [NSMutableDictionary dictionary];
                                desc[@"class"] = NSStringFromClass([item class]);
                                desc[@"description"] = [item description];

                                // Try to get name
                                if ([item respondsToSelector:@selector(name)]) {
                                    id name = ((id (*)(id, SEL))objc_msgSend)(item, @selector(name));
                                    if (name) desc[@"name"] = name;
                                }
                                // Try to get mediaType
                                if ([item respondsToSelector:@selector(mediaType)]) {
                                    long long mt = ((long long (*)(id, SEL))objc_msgSend)(item, @selector(mediaType));
                                    desc[@"mediaType"] = @(mt);
                                }

                                [itemDescs addObject:desc];
                            }
                            state[@"items"] = itemDescs;
                        }
                    }

                    // Get hasContainedItems
                    if ([sequence respondsToSelector:@selector(hasContainedItems)]) {
                        BOOL has = ((BOOL (*)(id, SEL))objc_msgSend)(sequence, @selector(hasContainedItems));
                        state[@"hasItems"] = @(has);
                    }
                } else {
                    state[@"sequence"] = [NSNull null];
                }
            }

            // Get playhead time (CMTime struct - value/timescale/flags/epoch)
            SEL ptSel = @selector(playheadTime);
            if ([timeline respondsToSelector:ptSel]) {
                // CMTime is {value:int64, timescale:int32, flags:uint32, epoch:int64}
                // Total 24 bytes. We need to use objc_msgSend_stret or check struct return
                typedef struct { int64_t value; int32_t timescale; uint32_t flags; int64_t epoch; } CMTime;
                CMTime t;
                // On arm64, small structs are returned in registers
                t = ((CMTime (*)(id, SEL))STRET_MSG)(timeline, ptSel);
                state[@"playheadTime"] = @{
                    @"value": @(t.value),
                    @"timescale": @(t.timescale),
                    @"seconds": (t.timescale > 0) ? @((double)t.value / t.timescale) : @(0)
                };
            }

            result = state;
        } @catch (NSException *e) {
            result = @{@"error": [NSString stringWithFormat:@"Exception: %@", e.reason]};
        }
    });

    return result;
}

#pragma mark - Transcript Handlers
//
// These proxy calls to SpliceKitTranscriptPanel for text-based editing.
// The transcript panel does the heavy lifting — transcribing audio, managing
// word/silence data, and performing timeline edits when words are deleted/moved.
// Most handlers just forward parameters and return the panel's result.
//

static NSDictionary *SpliceKit_handleTranscriptOpen(NSDictionary *params) {
    NSString *fileURL = params[@"fileURL"];
    BOOL forceRetranscribe = [params[@"forceRetranscribe"] boolValue];
    __block BOOL startedTranscription = NO;
    __block BOOL restoredTranscript = NO;
    __block BOOL alreadyTranscribing = NO;

    SpliceKit_executeOnMainThread(^{
        SpliceKitTranscriptPanel *panel = [SpliceKitTranscriptPanel sharedPanel];
        [panel showPanel];

        if (fileURL) {
            NSURL *url = [NSURL fileURLWithPath:fileURL];
            double timelineStart = [params[@"timelineStart"] doubleValue];
            double trimStart = [params[@"trimStart"] doubleValue];
            double trimDuration = [params[@"trimDuration"] doubleValue] ?: HUGE_VAL;
            [panel transcribeFromURL:url timelineStart:timelineStart trimStart:trimStart trimDuration:trimDuration];
            startedTranscription = YES;
        } else if (!forceRetranscribe && panel.status == SpliceKitTranscriptStatusReady && panel.words.count > 0) {
            restoredTranscript = YES;
        } else if (!forceRetranscribe && panel.status == SpliceKitTranscriptStatusTranscribing) {
            alreadyTranscribing = YES;
        } else {
            [panel transcribeTimeline];
            startedTranscription = YES;
        }
    });

    if (startedTranscription) {
        return @{
            @"status": @"ok",
            @"message": @"Transcript panel opened. Transcription started. Use transcript.getState to check progress.",
            @"transcriptionStarted": @YES,
        };
    }
    if (alreadyTranscribing) {
        return @{
            @"status": @"ok",
            @"message": @"Transcript panel opened. Transcription already in progress. Use transcript.getState to check progress.",
            @"transcriptionStarted": @NO,
        };
    }
    return @{
        @"status": @"ok",
        @"message": restoredTranscript ? @"Transcript panel opened. Restored persisted transcript." : @"Transcript panel opened.",
        @"transcriptionStarted": @NO,
    };
}

static NSDictionary *SpliceKit_handleTranscriptClose(NSDictionary *params) {
    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(0.5 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{
        [[SpliceKitTranscriptPanel sharedPanel] hidePanel];
    });
    return @{@"status": @"ok"};
}

static NSDictionary *SpliceKit_handleTranscriptGetState(NSDictionary *params) {
    // Check for project switch before returning state — ensures stale transcript
    // from a previous project is cleared/replaced with the current project's data.
    SpliceKitTranscriptPanel *panel = [SpliceKitTranscriptPanel sharedPanel];
    if (panel.status != SpliceKitTranscriptStatusTranscribing) {
        SpliceKit_executeOnMainThread(^{
            [panel ensurePersistedStateLoaded];
        });
    }
    return [panel getState] ?: @{@"status": @"idle"};
}

static NSDictionary *SpliceKit_handleTranscriptDeleteWords(NSDictionary *params) {
    NSUInteger startIndex = [params[@"startIndex"] unsignedIntegerValue];
    NSUInteger count = [params[@"count"] unsignedIntegerValue];
    if (count == 0) return @{@"error": @"count must be > 0"};

    __block NSDictionary *result = nil;
    SpliceKit_executeOnMainThread(^{
        result = [[SpliceKitTranscriptPanel sharedPanel] deleteWordsFromIndex:startIndex count:count];
    });
    return result ?: @{@"error": @"Operation failed"};
}

static NSDictionary *SpliceKit_handleTranscriptMoveWords(NSDictionary *params) {
    NSUInteger startIndex = [params[@"startIndex"] unsignedIntegerValue];
    NSUInteger count = [params[@"count"] unsignedIntegerValue];
    NSUInteger destIndex = [params[@"destIndex"] unsignedIntegerValue];
    if (count == 0) return @{@"error": @"count must be > 0"};

    __block NSDictionary *result = nil;
    SpliceKit_executeOnMainThread(^{
        result = [[SpliceKitTranscriptPanel sharedPanel] moveWordsFromIndex:startIndex count:count toIndex:destIndex];
    });
    return result ?: @{@"error": @"Operation failed"};
}

static NSDictionary *SpliceKit_handleTranscriptSearch(NSDictionary *params) {
    NSString *query = params[@"query"];
    if (!query || query.length == 0) return @{@"error": @"query is required"};

    return [[SpliceKitTranscriptPanel sharedPanel] searchTranscript:query] ?: @{@"error": @"Search failed"};
}

static NSDictionary *SpliceKit_handleTranscriptDeleteSilences(NSDictionary *params) {
    double minDuration = [params[@"minDuration"] doubleValue]; // 0 = delete all

    __block NSDictionary *result = nil;
    result = [[SpliceKitTranscriptPanel sharedPanel] deleteSilencesLongerThan:minDuration];
    return result ?: @{@"error": @"Operation failed"};
}

static NSDictionary *SpliceKit_handleTranscriptDetectAudioSilences(NSDictionary *params) {
    SpliceKitTranscriptPanel *panel = [SpliceKitTranscriptPanel sharedPanel];
    dispatch_async(dispatch_get_main_queue(), ^{
        [panel detectAudioSilencesWithCompletion:nil];
    });
    return @{
        @"status": @"started",
        @"message": @"FFmpeg timeline-audio analysis started. Use transcript.getState for confirmed and review candidates.",
    };
}

static NSDictionary *SpliceKit_handleTranscriptSetSilenceThreshold(NSDictionary *params) {
    double threshold = [params[@"threshold"] doubleValue];
    if (threshold <= 0) return @{@"error": @"threshold must be > 0"};

    SpliceKitTranscriptPanel *panel = [SpliceKitTranscriptPanel sharedPanel];
    panel.silenceThreshold = threshold;
    [panel redetectSilencesAndRefreshUI];

    return @{@"status": @"ok", @"silenceThreshold": @(threshold), @"silenceCount": @(panel.silences.count)};
}

static NSDictionary *SpliceKit_handleTranscriptSetEngine(NSDictionary *params) {
    NSString *engineName = params[@"engine"];
    if (!engineName) return @{@"error": @"engine is required ('fcpNative', 'appleSpeech', 'parakeetV3', 'parakeetV2', 'whisperLargeV3Turbo', 'whisperLargeV3')"};

    SpliceKitTranscriptPanel *panel = [SpliceKitTranscriptPanel sharedPanel];
    if ([engineName isEqualToString:@"fcpNative"]) {
        panel.engine = SpliceKitTranscriptEngineFCPNative;
    } else if ([engineName isEqualToString:@"appleSpeech"]) {
        panel.engine = SpliceKitTranscriptEngineAppleSpeech;
    } else if ([engineName isEqualToString:@"parakeetV3"] || [engineName isEqualToString:@"parakeet"]) {
        panel.engine = SpliceKitTranscriptEngineParakeet;
        panel.parakeetModelVersion = @"v3";
    } else if ([engineName isEqualToString:@"parakeetV2"]) {
        panel.engine = SpliceKitTranscriptEngineParakeet;
        panel.parakeetModelVersion = @"v2";
    } else {
        return @{@"error": @"Unknown engine. Use 'fcpNative', 'appleSpeech', 'parakeetV3', 'parakeetV2', 'whisperLargeV3Turbo', or 'whisperLargeV3'"};
    }
    return @{@"status": @"ok", @"engine": engineName};
}

static NSDictionary *SpliceKit_handleTranscriptSetSpeaker(NSDictionary *params) {
    NSString *speaker = params[@"speaker"];
    NSUInteger startIndex = [params[@"startIndex"] unsignedIntegerValue];
    NSUInteger count = [params[@"count"] unsignedIntegerValue];
    if (!speaker || speaker.length == 0) return @{@"error": @"speaker name is required"};
    if (count == 0) return @{@"error": @"count must be > 0"};

    [[SpliceKitTranscriptPanel sharedPanel] setSpeaker:speaker forWordsFrom:startIndex count:count];
    return @{@"status": @"ok", @"speaker": speaker, @"startIndex": @(startIndex), @"count": @(count)};
}

#pragma mark - Social Media Captions
//
// Handlers for the social captions panel — word-by-word highlighted titles
// generated as FCPXML and imported into the timeline. The caption panel does
// the heavy lifting; these handlers just proxy parameters through.
//

static NSDictionary *SpliceKit_handleCaptionsOpen(NSDictionary *params) {
    NSString *fileURL = params[@"fileURL"];
    NSString *presetID = params[@"style"];
    __block BOOL startedTranscription = NO;
    __block BOOL restoredCaptions = NO;
    __block BOOL alreadyTranscribing = NO;

    SpliceKit_executeOnMainThread(^{
        SpliceKitCaptionPanel *panel = [SpliceKitCaptionPanel sharedPanel];
        if (presetID) {
            SpliceKitCaptionStyle *style = [SpliceKitCaptionStyle presetWithID:presetID];
            if (style) [panel setStyle:style];
        }
        [panel showPanel];
        if (fileURL) {
            [panel transcribeTimeline];
            startedTranscription = YES;
        } else if (panel.status == SpliceKitCaptionStatusReady && panel.words.count > 0) {
            restoredCaptions = YES;
        } else if (panel.status == SpliceKitCaptionStatusTranscribing) {
            alreadyTranscribing = YES;
        } else if (panel.words.count == 0) {
            [panel transcribeTimeline];
            startedTranscription = YES;
        }
    });

    if (startedTranscription) {
        return @{
            @"status": @"ok",
            @"message": @"Caption panel opened. Transcription started. Use captions.getState to check progress.",
            @"transcriptionStarted": @YES,
        };
    }
    if (alreadyTranscribing) {
        return @{
            @"status": @"ok",
            @"message": @"Caption panel opened. Transcription already in progress. Use captions.getState to check progress.",
            @"transcriptionStarted": @NO,
        };
    }
    return @{
        @"status": @"ok",
        @"message": restoredCaptions ? @"Caption panel opened. Restored persisted captions." : @"Caption panel opened.",
        @"transcriptionStarted": @NO,
    };
}

static NSDictionary *SpliceKit_handleCaptionsClose(NSDictionary *params) {
    dispatch_async(dispatch_get_main_queue(), ^{
        [[SpliceKitCaptionPanel sharedPanel] hidePanel];
    });
    return @{@"status": @"ok"};
}

static NSDictionary *SpliceKit_handleCaptionsGetState(NSDictionary *params) {
    return [[SpliceKitCaptionPanel sharedPanel] getState] ?: @{@"status": @"idle"};
}

static NSDictionary *SpliceKit_handleCaptionsGetStyles(NSDictionary *params) {
    NSArray *presets = [SpliceKitCaptionStyle builtInPresets];
    NSMutableArray *list = [NSMutableArray array];
    for (SpliceKitCaptionStyle *s in presets) {
        [list addObject:[s toDictionary]];
    }
    return @{@"styles": list, @"count": @(list.count)};
}

static NSDictionary *SpliceKit_handleCaptionsSetStyle(NSDictionary *params) {
    NSMutableDictionary *normalizedParams = [params mutableCopy];
    id yOffset = normalizedParams[@"customYOffset"] ?: normalizedParams[@"positionY"] ?: normalizedParams[@"position_y"];
    if (yOffset) {
        normalizedParams[@"customYOffset"] = yOffset;
        normalizedParams[@"position"] = @"custom";
    }

    NSString *presetID = normalizedParams[@"presetID"];
    SpliceKitCaptionStyle *style = nil;

    if (presetID) {
        style = [SpliceKitCaptionStyle presetWithID:presetID];
        if (!style) return @{@"error": [NSString stringWithFormat:@"Unknown preset: %@", presetID]};
        // Merge all params as overrides on top of the preset
        NSMutableDictionary *merged = [[style toDictionary] mutableCopy];
        for (NSString *key in normalizedParams) {
            if (![key isEqualToString:@"presetID"]) merged[key] = normalizedParams[key];
        }
        style = [SpliceKitCaptionStyle fromDictionary:merged];
    } else {
        style = [SpliceKitCaptionStyle fromDictionary:normalizedParams];
    }

    [[SpliceKitCaptionPanel sharedPanel] setStyle:style];
    return @{@"status": @"ok", @"style": [style toDictionary]};
}

static NSDictionary *SpliceKit_handleCaptionsSetGrouping(NSDictionary *params) {
    SpliceKitCaptionPanel *panel = [SpliceKitCaptionPanel sharedPanel];
    NSString *mode = params[@"mode"];
    if ([mode isEqualToString:@"words"]) panel.groupingMode = SpliceKitCaptionGroupingByWordCount;
    else if ([mode isEqualToString:@"sentence"]) panel.groupingMode = SpliceKitCaptionGroupingBySentence;
    else if ([mode isEqualToString:@"time"]) panel.groupingMode = SpliceKitCaptionGroupingByTime;
    else if ([mode isEqualToString:@"chars"]) panel.groupingMode = SpliceKitCaptionGroupingByCharCount;
    else if ([mode isEqualToString:@"social"]) panel.groupingMode = SpliceKitCaptionGroupingSocial;

    if (params[@"maxWords"]) panel.maxWordsPerSegment = [params[@"maxWords"] unsignedIntegerValue];
    if (params[@"maxChars"]) panel.maxCharsPerSegment = [params[@"maxChars"] unsignedIntegerValue];
    if (params[@"maxSeconds"]) panel.maxSecondsPerSegment = [params[@"maxSeconds"] doubleValue];

    [panel regroupSegments];
    return @{@"status": @"ok", @"segmentCount": @(panel.segments.count)};
}

static NSDictionary *SpliceKit_handleCaptionsGenerate(NSDictionary *params) {
    SpliceKitCaptionPanel *panel = [SpliceKitCaptionPanel sharedPanel];

    // Support one-shot: set style + grouping + generate in one call
    NSDictionary *keyMap = @{
        @"word_highlight": @"wordByWordHighlight",
        @"all_caps": @"allCaps",
        @"font_size": @"fontSize",
        @"font_face": @"fontFace",
        @"outline_width": @"outlineWidth",
        @"position_y": @"customYOffset",
        @"positionY": @"customYOffset",
    };
    BOOL hasCustomY = (params[@"customYOffset"] || params[@"positionY"] || params[@"position_y"]);
    BOOL hasStyleParams = NO;
    for (NSString *key in params) {
        if (![key isEqualToString:@"maxWords"]) {
            hasStyleParams = YES;
            break;
        }
    }

    if (hasStyleParams) {
        SpliceKitCaptionStyle *style = [panel currentStyle];
        NSString *pid = params[@"style"] ?: params[@"presetID"];
        if (pid) {
            SpliceKitCaptionStyle *presetStyle = [SpliceKitCaptionStyle presetWithID:pid];
            if (presetStyle) style = presetStyle;
        }

        NSMutableDictionary *merged = [[style toDictionary] mutableCopy];
        for (NSString *key in params) {
            if ([key isEqualToString:@"style"] || [key isEqualToString:@"presetID"] ||
                [key isEqualToString:@"maxWords"]) continue;
            NSString *mappedKey = keyMap[key] ?: key;
            merged[mappedKey] = params[key];
        }
        if (hasCustomY) merged[@"position"] = @"custom";
        style = [SpliceKitCaptionStyle fromDictionary:merged];
        [panel setStyle:style];
    }
    if (params[@"maxWords"]) {
        panel.maxWordsPerSegment = [params[@"maxWords"] unsignedIntegerValue];
        [panel regroupSegments];
    }

    // Run on background thread — generateCaptions touches FCP on the main thread
    // as needed, then stores the final result on the caption panel for getState.
    dispatch_async(dispatch_get_global_queue(QOS_CLASS_USER_INITIATED, 0), ^{
        NSDictionary *genResult = [panel generateCaptions];
        SpliceKit_log(@"[Captions] Generate result: %@", genResult);
    });
    return @{@"status": @"ok", @"message": @"Caption generation started. Check captions.getState for results."};
}

static NSDictionary *SpliceKit_handleCaptionsExportSRT(NSDictionary *params) {
    NSString *path = params[@"path"];
    if (!path) return @{@"error": @"path parameter required"};
    return [[SpliceKitCaptionPanel sharedPanel] exportSRT:path];
